            auto bwt_buf = mtf_decode(mtf_buf.data(), mtf_buf.size());
            return bwt_decode(bwt_buf.data(), bwt_buf.size(), primary_index);
        }
        else if (block_type == 0x02 || block_type == 0x03) {
