std::string BPETokenizer::decode(const std::vector<int>& tokens) const {
    std::string result;
    for (int token_id : tokens) {
        // Skip special tokens
        if (token_id == pad_token_id_ || token_id == bos_token_id_ || token_id == eos_token_id_) {
            continue;
        }

        auto it = id_to_token_.find(token_id);
        if (it != id_to_token_.end()) {
            result += it->second;
        } else {
            result += "<UNK>";
        }
    }
    return result;
}

std::string BPETokenizer::token_to_string(int token_id) const {
    auto it = id_to_token_.find(token_id);
    return (it != id_to_token_.end()) ? it->second : "<UNK>";
}

int BPETokenizer::string_to_token(const std::string& token) const {
    auto it = token_to_id_.find(token);
    return (it != token_to_id_.end()) ? it->second : unk_token_id_;
}

void BPETokenizer::save(const std::string& path) const {
    std::ofstream file(path, std::ios::binary);
    if (!file) {
        std::cerr << "[BPE] Error: Cannot save to " << path << "\n";
        return;
    }

    // Write vocab size
    int vocab_size = token_to_id_.size();
    file.write(reinterpret_cast<const char*>(&vocab_size), sizeof(vocab_size));

    // Write tokens
    for (const auto& [token, id] : token_to_id_) {
        int token_len = token.size();
        file.write(reinterpret_cast<const char*>(&token_len), sizeof(token_len));
        file.write(token.data(), token_len);
        file.write(reinterpret_cast<const char*>(&id), sizeof(id));
    }

    // Write merges
    int num_merges = merges_.size();
    file.write(reinterpret_cast<const char*>(&num_merges), sizeof(num_merges));
    for (const auto& merge : merges_) {
        int pair_len = merge.pair.size();
        file.write(reinterpret_cast<const char*>(&pair_len), sizeof(pair_len));
        file.write(merge.pair.data(), pair_len);

        int merged_len = merge.merged.size();
        file.write(reinterpret_cast<const char*>(&merged_len), sizeof(merged_len));
        file.write(merge.merged.data(), merged_len);

        file.write(reinterpret_cast<const char*>(&merge.priority), sizeof(merge.priority));
    }

    std::cerr << "[BPE] Saved tokenizer to " << path << "\n";
}

void BPETokenizer::load(const std::string& path) {
    std::ifstream file(path, std::ios::binary);
    if (!file) {
        std::cerr << "[BPE] Error: Cannot load from " << path << "\n";
        return;
    }

    token_to_id_.clear();
    id_to_token_.clear();
    merges_.clear();

    // Read vocab size
    int vocab_size;
    file.read(reinterpret_cast<char*>(&vocab_size), sizeof(vocab_size));

    // Read tokens
    for (int i = 0; i < vocab_size; i++) {
        int token_len;
        file.read(reinterpret_cast<char*>(&token_len), sizeof(token_len));

        std::string token(token_len, '\0');
        file.read(&token[0], token_len);

        int id;
        file.read(reinterpret_cast<char*>(&id), sizeof(id));

        token_to_id_[token] = id;
        id_to_token_[id] = token;
    }

    // Read merges
    int num_merges;
    file.read(reinterpret_cast<char*>(&num_merges), sizeof(num_merges));
    for (int i = 0; i < num_merges; i++) {
        Merge merge;

        int pair_len;
        file.read(reinterpret_cast<char*>(&pair_len), sizeof(pair_len));
        merge.pair.resize(pair_len);
        file.read(&merge.pair[0], pair_len);

        int merged_len;
        file.read(reinterpret_cast<char*>(&merged_len), sizeof(merged_len));
        merge.merged.resize(merged_len);
        file.read(&merge.merged[0], merged_len);

        file.read(reinterpret_cast<char*>(&merge.priority), sizeof(merge.priority));

        merges_.push_back(merge);
    }

    std::cerr << "[BPE] Loaded tokenizer from " << path
              << " (vocab: " << token_to_id_.size() << ", merges: " << merges_.size() << ")\n";
}

uint32_t bwt_encode(const uint8_t* data, size_t N, uint8_t* out) {
    if (N == 0) return 0;
    if (N == 1) { out[0] = data[0]; return 0; }

    std::vector<int32_t> SA(N), rank_(N), tmp(N), cnt, buf;

    // Initialize rank by first character
    for (size_t i = 0; i < N; ++i) rank_[i] = data[i];

    // Initial sort by first character
    {
        cnt.assign(256, 0);
        for (size_t i = 0; i < N; ++i) cnt[data[i]]++;
        buf.resize(N);
        int32_t s = 0;
        for (auto& c : cnt) { int32_t t = c; c = s; s += t; }
        for (size_t i = 0; i < N; ++i) buf[cnt[data[i]]++] = (int32_t)i;
        SA = buf;
    }

    // Initial ranks = character values
    // (rank_[i] already = data[i], which is correct)

    for (int32_t gap = 1; gap < (int32_t)N; gap <<= 1) {
        // Build secondary key: rank2[i] = rank_[(i+gap)%N]
        // Sort SA by (rank_[SA[i]], rank_[(SA[i]+gap)%N]) using two radix passes.

        // Current max rank value (after rank recomputation it's 0..N-1)
        int32_t max_rank = rank_[SA[N-1]];

        // Pass 1: sort by secondary key rank_[(i+gap)%N]
        // Build a "shifted" SA to sort by: each element i → sort key rank_[(i+gap)%N]
        // We need a stable sort here, using the current SA as input.
        // Strategy: create secondary sorted order, then stable-sort by primary.

        // Create pos_by_secondary[j] = sorted order of positions by rank2
        // rank2[i] = rank_[(i+gap)%N]
        // We want to sort 0..N-1 by rank2[i]:
        std::vector<int32_t> sa2(N);
        std::iota(sa2.begin(), sa2.end(), 0);
        {
            cnt.assign(max_rank + 1, 0);
            for (size_t i = 0; i < N; ++i) cnt[rank_[(i+gap)%N]]++;
            buf.resize(N);
            int32_t s = 0;
            for (auto& c : cnt) { int32_t t = c; c = s; s += t; }
            for (size_t i = 0; i < N; ++i) buf[cnt[rank_[(i+gap)%N]]++] = (int32_t)i;
            sa2 = buf;
        }

        // Pass 2: stable sort sa2 by primary key rank_[i]
        {
            cnt.assign(max_rank + 1, 0);
            for (int32_t x : sa2) cnt[rank_[x]]++;
            buf.resize(N);
            int32_t s = 0;
            for (auto& c : cnt) { int32_t t = c; c = s; s += t; }
            for (int32_t x : sa2) buf[cnt[rank_[x]]++] = x;
            SA = buf;
        }

        // Recompute ranks from sorted order
        tmp[SA[0]] = 0;
        for (size_t i = 1; i < N; ++i) {
            tmp[SA[i]] = tmp[SA[i-1]];
            if (rank_[SA[i]] != rank_[SA[i-1]] ||
                rank_[(SA[i] + gap) % (int32_t)N] !=
                rank_[(SA[i-1] + gap) % (int32_t)N])
                ++tmp[SA[i]];
        }
        rank_ = tmp;

        // Early exit if all ranks are unique
        if (rank_[SA[N-1]] == (int32_t)(N-1)) break;
    }

    // Build BWT: last column = data[(SA[i] + N - 1) % N]
    uint32_t primary = 0;
    for (size_t i = 0; i < N; ++i) {
        out[i] = data[(SA[i] + N - 1) % N];
        if (SA[i] == 0) primary = (uint32_t)i;
    }
    return primary;
}

std::vector<uint8_t> bwt_decode(const uint8_t* bwt, size_t N, uint32_t primary_index) {
    if (N == 0) return {};
    if (N == 1) return {bwt[0]};

    // Count occurrences and build cumulative table C[]
    uint32_t count[256] = {};
    for (size_t i = 0; i < N; ++i) count[bwt[i]]++;

    uint32_t C[256] = {};
    for (int c = 1; c < 256; ++c) C[c] = C[c-1] + count[c-1];

    // Build T[]: L→F mapping
    // T[i] = C[bwt[i]] + (rank of bwt[i] among all j<=i with bwt[j]==bwt[i])
    std::vector<uint32_t> T(N);
    uint32_t rank_so_far[256] = {};
    for (size_t i = 0; i < N; ++i) {
        uint8_t c = bwt[i];
        T[i] = C[c] + rank_so_far[c];
        rank_so_far[c]++;
    }

    // Follow T[] starting at primary_index to reconstruct original (in reverse)
    // bwt[primary_index] = data[N-1], T[primary_index] -> data[N-2], etc.
    std::vector<uint8_t> out(N);
    uint32_t idx = primary_index;
    for (size_t i = 0; i < N; ++i) {
        out[N - 1 - i] = bwt[idx];
        idx = T[idx];
    }
    return out;
}

std::vector<uint8_t> mtf_encode(const uint8_t* data, size_t N) {
    uint8_t list[256];
    for (int i = 0; i < 256; ++i) list[i] = (uint8_t)i;

    std::vector<uint8_t> out(N);
    for (size_t i = 0; i < N; ++i) {
        uint8_t b = data[i];
        // Find rank
        int rank = 0;
        while (list[rank] != b) ++rank;
        out[i] = (uint8_t)rank;
        // Move to front
        memmove(list + 1, list, rank);
        list[0] = b;
    }
    return out;
}

std::vector<uint8_t> mtf_decode(const uint8_t* ranks, size_t N) {
    uint8_t list[256];
    for (int i = 0; i < 256; ++i) list[i] = (uint8_t)i;

    std::vector<uint8_t> out(N);
    for (size_t i = 0; i < N; ++i) {
        int rank = ranks[i];
        uint8_t b = list[rank];
        out[i] = b;
        memmove(list + 1, list, rank);
        list[0] = b;
    }
    return out;
}

std::vector<uint8_t> rle_zeros_encode(const uint8_t* data, size_t N) {
    std::vector<uint8_t> out;
    out.reserve(N);

    size_t i = 0;
    while (i < N) {
        if (data[i] != 0) {
            out.push_back(data[i]);
            ++i;
        } else {
            // Count run of zeros (up to 256 at a time)
            size_t k = 0;
            while (i < N && data[i] == 0 && k < 256) { ++k; ++i; }
            out.push_back(0x00);
            out.push_back((uint8_t)(k - 1));  // 0 means 1 zero, 255 means 256 zeros
        }
    }
    return out;
}

std::vector<uint8_t> rle_zeros_decode(const uint8_t* rle, size_t rle_len) {
    std::vector<uint8_t> out;
    out.reserve(rle_len);  // rough lower bound

    size_t i = 0;
    while (i < rle_len) {
        if (rle[i] != 0) {
            out.push_back(rle[i]);
            ++i;
        } else {
            if (i + 1 >= rle_len)
                throw std::runtime_error("rle_zeros_decode: truncated zero-run pair");
            uint32_t count = (uint32_t)rle[i+1] + 1;  // 1..256
            for (uint32_t z = 0; z < count; ++z)
                out.push_back(0x00);
            i += 2;
        }
    }
    return out;
}

static bool cpu_has_sse2() {
    // SSE2 is guaranteed on all x86-64 CPUs
    return true;
}

static bool cpu_has_avx2() {
    static int cached = -1;
    if (cached >= 0) return cached;

#ifdef _MSC_VER
    int cpuInfo[4];
    __cpuid(cpuInfo, 1);
    bool hasAVX = (cpuInfo[2] & (1 << 28)) != 0;
    if (!hasAVX) { cached = 0; return false; }

    __cpuid(cpuInfo, 7);
    cached = (cpuInfo[1] & (1 << 5)) != 0;
#else
    unsigned int eax, ebx, ecx, edx;
    if (__get_cpuid(1, &eax, &ebx, &ecx, &edx)) {
        bool hasAVX = (ecx & (1 << 28)) != 0;
        if (!hasAVX) { cached = 0; return false; }
    }

    if (__get_cpuid_count(7, 0, &eax, &ebx, &ecx, &edx)) {
        cached = (ebx & (1 << 5)) != 0;
    } else {
        cached = 0;
    }
#endif

    return cached;
}

std::vector<uint8_t> mtf_encode_simd(const uint8_t* data, size_t N) {
    uint8_t list[256];
    for (int i = 0; i < 256; ++i) list[i] = (uint8_t)i;

    std::vector<uint8_t> out(N);

    // Use SSE2 for searching
    for (size_t i = 0; i < N; ++i) {
        uint8_t b = data[i];
        int rank = 0;

        // SSE2: Compare 16 bytes at a time
        #ifdef __SSE2__
        __m128i search = _mm_set1_epi8(b);

        // Search in chunks of 16
        for (int j = 0; j < 256; j += 16) {
            __m128i chunk = _mm_loadu_si128((__m128i*)(list + j));
            __m128i cmp = _mm_cmpeq_epi8(chunk, search);
            int mask = _mm_movemask_epi8(cmp);

            if (mask) {
                // Found in this chunk - count trailing zeros to find position
                #ifdef _MSC_VER
                unsigned long pos;
                _BitScanForward(&pos, mask);
                rank = j + pos;
                #else
                rank = j + __builtin_ctz(mask);
                #endif
                break;
            }
        }
        #else
        // Fallback: linear search
        while (list[rank] != b) ++rank;
        #endif

        out[i] = (uint8_t)rank;

        // Move to front - keep using memmove (it's already optimized)
        if (rank > 0) {
            memmove(list + 1, list, rank);
            list[0] = b;
        }
    }

    return out;
}

std::vector<uint8_t> rle_zeros_encode_simd(const uint8_t* data, size_t N) {
    std::vector<uint8_t> out;
    out.reserve(N);

    size_t i = 0;

    #ifdef __SSE2__
    __m128i zero_vec = _mm_setzero_si128();

    while (i < N) {
        if (data[i] != 0) {
            out.push_back(data[i]);
            ++i;
        } else {
            // Count run of zeros using SIMD
            size_t run_start = i;
            size_t k = 0;

            // Process 16 bytes at a time
            while (i + 16 <= N && k < 256) {
                __m128i chunk = _mm_loadu_si128((__m128i*)(data + i));
                __m128i cmp = _mm_cmpeq_epi8(chunk, zero_vec);
                int mask = _mm_movemask_epi8(cmp);

                if (mask == 0xFFFF) {
                    // All 16 bytes are zero
                    i += 16;
                    k += 16;
                } else if (mask == 0) {
                    // No zeros in this chunk
                    break;
                } else {
                    // Partial zeros - count how many
                    #ifdef _MSC_VER
                    unsigned long pos;
                    _BitScanForward(&pos, ~mask);
                    size_t count = pos;
                    #else
                    size_t count = __builtin_ctz(~mask);
                    #endif
                    i += count;
                    k += count;
                    break;
                }
            }

            // Finish counting any remaining zeros (scalar)
            while (i < N && data[i] == 0 && k < 256) {
                ++k;
                ++i;
            }

            if (k > 0) {
                out.push_back(0x00);
                out.push_back((uint8_t)(k - 1));
            }
        }
    }
    #else
    // Fallback to scalar version
    while (i < N) {
        if (data[i] != 0) {
            out.push_back(data[i]);
            ++i;
        } else {
            size_t k = 0;
            while (i < N && data[i] == 0 && k < 256) {
                ++k;
                ++i;
            }
            out.push_back(0x00);
            out.push_back((uint8_t)(k - 1));
        }
    }
    #endif

    return out;
}

void fast_memcpy(void* dest, const void* src, size_t n) {
    #ifdef __AVX2__
    if (cpu_has_avx2() && n >= 32) {
        uint8_t* d = (uint8_t*)dest;
        const uint8_t* s = (const uint8_t*)src;

        // Copy 32 bytes at a time with AVX2
        size_t avx_chunks = n / 32;
        for (size_t i = 0; i < avx_chunks; ++i) {
            __m256i chunk = _mm256_loadu_si256((__m256i*)(s + i * 32));
            _mm256_storeu_si256((__m256i*)(d + i * 32), chunk);
        }

        // Copy remaining bytes
        size_t remaining = n % 32;
        if (remaining > 0) {
            memcpy(d + avx_chunks * 32, s + avx_chunks * 32, remaining);
        }
        return;
    }
    #endif

    #ifdef __SSE2__
    if (n >= 16) {
        uint8_t* d = (uint8_t*)dest;
        const uint8_t* s = (const uint8_t*)src;

        // Copy 16 bytes at a time with SSE2
        size_t sse_chunks = n / 16;
        for (size_t i = 0; i < sse_chunks; ++i) {
            __m128i chunk = _mm_loadu_si128((__m128i*)(s + i * 16));
            _mm_storeu_si128((__m128i*)(d + i * 16), chunk);
        }

        // Copy remaining bytes
        size_t remaining = n % 16;
        if (remaining > 0) {
            memcpy(d + sse_chunks * 16, s + sse_chunks * 16, remaining);
        }
        return;
    }
    #endif

    // Fallback
    memcpy(dest, src, n);
}

std::vector<uint8_t> mtf_encode_optimized(const uint8_t* data, size_t N) {
    #ifdef __SSE2__
    if (cpu_has_sse2()) {
        return mtf_encode_simd(data, N);
    }
    #endif
    return mtf_encode(data, N);  // Fallback to scalar
}

std::vector<uint8_t> rle_zeros_encode_optimized(const uint8_t* data, size_t N) {
    #ifdef __SSE2__
    if (cpu_has_sse2()) {
        return rle_zeros_encode_simd(data, N);
    }
    #endif
    return rle_zeros_encode(data, N);  // Fallback to scalar
}

    std::string exec_python_cloud(const char* cmd) {
        std::array<char, 256> buffer;
        std::string result;
#ifdef _WIN32
        std::unique_ptr<FILE, decltype(&_pclose)> pipe(_popen(cmd, "r"), _pclose);
#else
        std::unique_ptr<FILE, decltype(&pclose)> pipe(popen(cmd, "r"), pclose);
#endif
        if (!pipe) {
            return "Error: Could not execute Python API call.";
        }
        while (fgets(buffer.data(), buffer.size(), pipe.get()) != nullptr) {
            result += buffer.data();
        }
        return result;
    }

std::string escape_shell(const std::string& str) {
    std::string escaped = "\"";
    for (char c : str) {
        if (c == '"') escaped += "\\\"";
        else escaped += c;
    }
    escaped += "\"";
    return escaped;
}

