    auto cb = [&](size_t d, size_t t, int active) {
        if (progress) progress("cmix", global_done + d, global_total, active);
    };

    auto coded = cmix_encode(data, len, cb);
    size_t cmix_size = 1 + 4 + coded.size();

    std::vector<uint8_t> out;
