float ConversationMemory::question_similarity(const std::string& q1, const std::string& q2) const {
    // Simple word overlap similarity
    std::istringstream iss1(q1), iss2(q2);
    std::vector<std::string> words1, words2;
    std::string word;

    while (iss1 >> word) {
        // Convert to lowercase
        std::transform(word.begin(), word.end(), word.begin(), ::tolower);
        words1.push_back(word);
    }

    while (iss2 >> word) {
        std::transform(word.begin(), word.end(), word.begin(), ::tolower);
        words2.push_back(word);
    }

    if (words1.empty() || words2.empty()) return 0.0f;

    // Count overlap
    int overlap = 0;
    for (const auto& w1 : words1) {
        if (std::find(words2.begin(), words2.end(), w1) != words2.end()) {
            overlap++;
        }
    }

    return static_cast<float>(overlap) / std::max(words1.size(), words2.size());
}

int ConversationMemory::find_similar_question(const std::string& question, float threshold) const {
    float max_sim = 0.0f;
    int best_turn_id = -1;

    for (const auto& turn : history) {
        float sim = question_similarity(question, turn.user_message);
        if (sim > max_sim && sim >= threshold) {
            max_sim = sim;
            best_turn_id = turn.turn_id;
        }
    }

    return best_turn_id;
}

bool ConversationMemory::should_ask_for_help(const std::string& question, float confidence) const {
    // Low confidence -> ask for help
    if (confidence < 0.5f) {
        return true;
    }

    // Check if similar questions got negative feedback
    for (const auto& turn : history) {
        float sim = question_similarity(question, turn.user_message);
        if (sim > 0.7f && (turn.user_satisfaction < 0.3f || turn.was_corrected)) {
            // Similar question was answered poorly before
            return true;
        }
    }

    return false;
}

ConversationMemory::Stats ConversationMemory::get_stats() const {
    Stats stats;
    stats.total_turns = history.size();

    float sum_confidence = 0.0f;
    float sum_satisfaction = 0.0f;
    int satisfaction_count = 0;

    for (const auto& turn : history) {
        sum_confidence += turn.confidence;

        if (turn.user_satisfaction >= 0.0f) {
            sum_satisfaction += turn.user_satisfaction;
            satisfaction_count++;
            stats.turns_with_feedback++;

            if (turn.user_satisfaction >= 0.8f) {
                stats.high_quality_turns++;
            }
        }

        if (turn.was_corrected) {
            stats.corrections++;
        }
    }

    if (stats.total_turns > 0) {
        stats.average_confidence = sum_confidence / stats.total_turns;
    }

    if (satisfaction_count > 0) {
        stats.average_satisfaction = sum_satisfaction / satisfaction_count;
    }

    return stats;
}

void ConversationMemory::save(const std::string& file_path) const {
    std::ofstream file(file_path, std::ios::binary);
    if (!file) {
        std::cerr << "[Memory] Error: Cannot save to " << file_path << "\n";
        return;
    }

    // Write header
    int history_size = history.size();
    file.write(reinterpret_cast<const char*>(&history_size), sizeof(history_size));
    file.write(reinterpret_cast<const char*>(&next_turn_id), sizeof(next_turn_id));

    // Write turns
    for (const auto& turn : history) {
        file.write(reinterpret_cast<const char*>(&turn.turn_id), sizeof(turn.turn_id));

        // Write strings
        int len = turn.user_message.length();
        file.write(reinterpret_cast<const char*>(&len), sizeof(len));
        file.write(turn.user_message.data(), len);

        len = turn.ai_response.length();
        file.write(reinterpret_cast<const char*>(&len), sizeof(len));
        file.write(turn.ai_response.data(), len);

        file.write(reinterpret_cast<const char*>(&turn.confidence), sizeof(turn.confidence));
        file.write(reinterpret_cast<const char*>(&turn.user_satisfaction), sizeof(turn.user_satisfaction));

        // Write sources
        int source_count = turn.sources.size();
        file.write(reinterpret_cast<const char*>(&source_count), sizeof(source_count));
        for (const auto& source : turn.sources) {
            len = source.length();
            file.write(reinterpret_cast<const char*>(&len), sizeof(len));
            file.write(source.data(), len);
        }

        file.write(reinterpret_cast<const char*>(&turn.timestamp), sizeof(turn.timestamp));
        file.write(reinterpret_cast<const char*>(&turn.was_corrected), sizeof(turn.was_corrected));

        len = turn.correction.length();
        file.write(reinterpret_cast<const char*>(&len), sizeof(len));
        file.write(turn.correction.data(), len);
    }

    std::cout << "[Memory] Saved " << history_size << " conversation turns\n";
}

void ConversationMemory::load(const std::string& file_path) {
    std::ifstream file(file_path, std::ios::binary);
    if (!file) {
        std::cerr << "[Memory] Error: Cannot load from " << file_path << "\n";
        return;
    }

    history.clear();

    // Read header
    int history_size;
    file.read(reinterpret_cast<char*>(&history_size), sizeof(history_size));
    file.read(reinterpret_cast<char*>(&next_turn_id), sizeof(next_turn_id));

    // Read turns
    for (int i = 0; i < history_size; i++) {
        Turn turn;

        file.read(reinterpret_cast<char*>(&turn.turn_id), sizeof(turn.turn_id));

        // Read strings
        int len;
        file.read(reinterpret_cast<char*>(&len), sizeof(len));
        turn.user_message.resize(len);
        file.read(&turn.user_message[0], len);

        file.read(reinterpret_cast<char*>(&len), sizeof(len));
        turn.ai_response.resize(len);
        file.read(&turn.ai_response[0], len);

        file.read(reinterpret_cast<char*>(&turn.confidence), sizeof(turn.confidence));
        file.read(reinterpret_cast<char*>(&turn.user_satisfaction), sizeof(turn.user_satisfaction));

        // Read sources
        int source_count;
        file.read(reinterpret_cast<char*>(&source_count), sizeof(source_count));
        for (int j = 0; j < source_count; j++) {
            file.read(reinterpret_cast<char*>(&len), sizeof(len));
            std::string source(len, '\0');
            file.read(&source[0], len);
            turn.sources.push_back(source);
        }

        file.read(reinterpret_cast<char*>(&turn.timestamp), sizeof(turn.timestamp));
        file.read(reinterpret_cast<char*>(&turn.was_corrected), sizeof(turn.was_corrected));

        file.read(reinterpret_cast<char*>(&len), sizeof(len));
        turn.correction.resize(len);
        file.read(&turn.correction[0], len);

        history.push_back(turn);
    }

    std::cout << "[Memory] Loaded " << history_size << " conversation turns\n";
}

void ConversationMemory::prune(int keep_recent) {
    while (static_cast<int>(history.size()) > keep_recent) {
        history.pop_front();
    }
}

DataLoader::DataLoader(const std::string& corpus_path,
                       BPETokenizer& tokenizer,
                       int max_seq_length,
                       int batch_size)
    : tokenizer_(tokenizer)
    , max_seq_length_(max_seq_length)
    , batch_size_(batch_size)
    , current_pos_(0)
    , corpus_size_(0)
    , num_batches_(0)
    , current_batch_(0)
    , eof_reached_(false)
{
    file_.open(corpus_path);
    if (!file_.is_open()) {
        std::cerr << "[ERROR] Cannot open corpus: " << corpus_path << "\n";
        return;
    }

    // Get corpus size
    file_.seekg(0, std::ios::end);
    corpus_size_ = file_.tellg();
    file_.seekg(0, std::ios::beg);

    std::cout << "[DATA LOADER] Initialized\n";
    std::cout << "  Corpus: " << corpus_path << "\n";
    std::cout << "  Size: " << (corpus_size_ / 1024 / 1024) << " MB\n";
    std::cout << "  Max sequence length: " << max_seq_length_ << "\n";
    std::cout << "  Batch size: " << batch_size_ << "\n";

    load_buffer();
}

DataLoader::~DataLoader() {
    if (file_.is_open()) {
        file_.close();
    }
}

void DataLoader::load_buffer() {
    buffer_.clear();
    std::string line;

    // Load batch_size * 10 lines into buffer (for efficiency)
    int lines_to_load = batch_size_ * 10;
    int loaded = 0;

    while (loaded < lines_to_load && std::getline(file_, line)) {
        // Skip empty or very short lines
        if (line.length() > 10) {
            buffer_.push_back(line);
            loaded++;
        }
    }

    if (buffer_.empty()) {
        eof_reached_ = true;
    }

    current_pos_ = 0;
}

TrainingBatch DataLoader::next_batch() {
    TrainingBatch batch;
    batch.batch_size = 0;
    batch.seq_len = max_seq_length_;

    // Collect batch_size examples
    while (batch.batch_size < batch_size_ && has_next()) {
        // Get next text
        if (current_pos_ >= buffer_.size()) {
            load_buffer();
            if (buffer_.empty()) break;
        }

        std::string text = buffer_[current_pos_++];

        // Tokenize
        auto tokens = tokenizer_.encode(text);

        // Skip if too short
        if (tokens.size() < 10) {
            continue;
        }

        // Truncate or pad to max_seq_length
        if (tokens.size() > (size_t)max_seq_length_) {
            tokens.resize(max_seq_length_);
        } else {
            // Pad with PAD token (0)
            while (tokens.size() < (size_t)max_seq_length_) {
                tokens.push_back(0);
            }
        }

        // Create targets (shifted by 1 position)
        std::vector<int> targets = tokens;
        targets.erase(targets.begin());
        targets.push_back(3);  // EOS token

        batch.tokens.push_back(tokens);
        batch.targets.push_back(targets);
        batch.batch_size++;
    }

    current_batch_++;
    return batch;
}

bool DataLoader::has_next() const {
    return !eof_reached_ || current_pos_ < buffer_.size();
}

void DataLoader::reset() {
    file_.clear();
    file_.seekg(0);
    current_pos_ = 0;
    current_batch_ = 0;
    eof_reached_ = false;
    load_buffer();

    std::cout << "[DATA LOADER] Reset to beginning\n";
}

EmbeddingTrainer::EmbeddingTrainer(int dim, int window, int neg_samples, int min_count)
    : dim(dim), window(window), neg_samples(neg_samples), min_count(min_count),
      rng(std::random_device{}())
{
}

void EmbeddingTrainer::init_embeddings() {
    std::uniform_real_distribution<float> dist(-0.5f / dim, 0.5f / dim);

    for (int i = 0; i < tokenizer.vocab_size(); i++) {
        // Target embeddings
        embeddings[i].resize(dim);
        for (int j = 0; j < dim; j++) {
            embeddings[i][j] = dist(rng);
        }

        // Context embeddings (separate for skip-gram)
        context_embeddings[i].resize(dim, 0.0f);
    }

    std::cout << "[Embeddings] Initialized " << tokenizer.vocab_size()
              << " embeddings of dimension " << dim << "\n";
}

void EmbeddingTrainer::build_neg_table() {
    std::cout << "[Embeddings] Building negative sampling table...\n";

    // Build frequency table (word -> count^0.75)
    std::vector<double> power_freqs;
    double total = 0.0;

    for (int i = 0; i < tokenizer.vocab_size(); i++) {
        std::string word = tokenizer.get_word(i);
        int freq = tokenizer.get_word_freq(word);
        if (freq == 0) freq = 1;

        double power = std::pow(freq, 0.75);
        power_freqs.push_back(power);
        total += power;
    }

    // Populate neg_table proportionally
    neg_table.clear();
    neg_table.reserve(NEG_TABLE_SIZE);

    int word_idx = 0;
    double cumulative = power_freqs[0] / total;

    for (int i = 0; i < NEG_TABLE_SIZE; i++) {
        double target = static_cast<double>(i) / NEG_TABLE_SIZE;

        while (cumulative < target && word_idx < static_cast<int>(power_freqs.size()) - 1) {
            word_idx++;
            cumulative += power_freqs[word_idx] / total;
        }

        neg_table.push_back(word_idx);
    }

    std::cout << "[Embeddings] Negative sampling table built ("
              << (NEG_TABLE_SIZE / 1000000) << "M entries)\n";
}

int EmbeddingTrainer::sample_negative() {
    std::uniform_int_distribution<int> dist(0, NEG_TABLE_SIZE - 1);
    return neg_table[dist(rng)];
}

float EmbeddingTrainer::dot_product(const std::vector<float>& a, const std::vector<float>& b) {
    float sum = 0.0f;
    for (size_t i = 0; i < a.size(); i++) {
        sum += a[i] * b[i];
    }
    return sum;
}

float EmbeddingTrainer::cosine_similarity(const std::vector<float>& a, const std::vector<float>& b) {
    float dot = 0.0f, mag_a = 0.0f, mag_b = 0.0f;

    for (size_t i = 0; i < a.size(); i++) {
        dot += a[i] * b[i];
        mag_a += a[i] * a[i];
        mag_b += b[i] * b[i];
    }

    mag_a = std::sqrt(mag_a);
    mag_b = std::sqrt(mag_b);

    if (mag_a < 1e-10f || mag_b < 1e-10f) return 0.0f;

    return dot / (mag_a * mag_b);
}

void EmbeddingTrainer::normalize(std::vector<float>& vec) {
    float mag = 0.0f;
    for (float v : vec) mag += v * v;
    mag = std::sqrt(mag);

    if (mag > 1e-10f) {
        for (float& v : vec) v /= mag;
    }
}

void EmbeddingTrainer::update_positive(int target, int context, float lr) {
    auto& target_emb = embeddings[target];
    auto& context_emb = context_embeddings[context];

    // Forward pass
    float score = dot_product(target_emb, context_emb);
    float pred = sigmoid(score);
    float gradient = (1.0f - pred) * lr;  // Positive sample: target = 1

    // Backward pass (gradient descent)
    for (int i = 0; i < dim; i++) {
        float grad_target = gradient * context_emb[i];
        float grad_context = gradient * target_emb[i];

        target_emb[i] += grad_target;
        context_emb[i] += grad_context;
    }
}

void EmbeddingTrainer::update_negative(int target, int negative, float lr) {
    auto& target_emb = embeddings[target];
    auto& neg_emb = context_embeddings[negative];

    // Forward pass
    float score = dot_product(target_emb, neg_emb);
    float pred = sigmoid(score);
    float gradient = (0.0f - pred) * lr;  // Negative sample: target = 0

    // Backward pass
    for (int i = 0; i < dim; i++) {
        float grad_target = gradient * neg_emb[i];
        float grad_neg = gradient * target_emb[i];

        target_emb[i] += grad_target;
        neg_emb[i] += grad_neg;
    }
}

