    const std::unordered_set<std::string>& exclude
) const

output:
std::vector<std::pair<std::string, float>> EmbeddingTrainer::find_nearest(
    const std::vector<float>& query_vec,
    int top_k,
    const std::unordered_set<std::string>& exclude
) const {
    std::vector<std::pair<std::string, float>> results;

    for (int i = 0; i < tokenizer.vocab_size(); i++) {
        std::string word = tokenizer.get_word(i);
        if (exclude.count(word)) continue;

        auto it = embeddings.find(i);
        if (it == embeddings.end()) continue;

        float sim = cosine_similarity(query_vec, it->second);
        results.push_back({word, sim});
    }

    std::sort(results.begin(), results.end(),
              [](const auto& a, const auto& b) { return a.second > b.second; });

    if (static_cast<int>(results.size()) > top_k) {
        results.resize(top_k);
    }

    return results;
}

std::vector<float> EmbeddingTrainer::sentence_embedding(const std::string& sentence) const {
    auto tokens = tokenizer.tokenize(sentence);
    std::vector<float> avg(dim, 0.0f);

    int count = 0;
    for (const auto& token : tokens) {
        auto emb = get_embedding(token);
        bool non_zero = false;
        for (float v : emb) {
            if (std::abs(v) > 1e-10f) {
                non_zero = true;
                break;
            }
        }

        if (non_zero) {
            for (int i = 0; i < dim; i++) {
                avg[i] += emb[i];
            }
            count++;
        }
    }

    if (count > 0) {
        for (int i = 0; i < dim; i++) {
            avg[i] /= count;
        }
    }

    return avg;
}

void EmbeddingTrainer::save(const std::string& file_path) const {
    std::ofstream file(file_path, std::ios::binary);
    if (!file) {
        std::cerr << "[Embeddings] Error: Cannot save to " << file_path << "\n";
        return;
    }

    // Write header
    int vocab_sz = tokenizer.vocab_size();
    file.write(reinterpret_cast<const char*>(&vocab_sz), sizeof(vocab_sz));
    file.write(reinterpret_cast<const char*>(&dim), sizeof(dim));

    // Write embeddings
    for (int i = 0; i < vocab_sz; i++) {
        std::string word = tokenizer.get_word(i);
        auto it = embeddings.find(i);

        if (it == embeddings.end()) continue;

        // Write word
        int word_len = word.length();
        file.write(reinterpret_cast<const char*>(&word_len), sizeof(word_len));
        file.write(word.data(), word_len);

        // Write embedding
        file.write(reinterpret_cast<const char*>(it->second.data()), dim * sizeof(float));
    }

    std::cout << "[Embeddings] Saved " << vocab_sz << " embeddings to " << file_path << "\n";
}

void EmbeddingTrainer::load(const std::string& file_path) {
    std::ifstream file(file_path, std::ios::binary);
    if (!file) {
        std::cerr << "[Embeddings] Error: Cannot load from " << file_path << "\n";
        return;
    }

    // Read header
    int vocab_sz;
    file.read(reinterpret_cast<char*>(&vocab_sz), sizeof(vocab_sz));
    file.read(reinterpret_cast<char*>(&dim), sizeof(dim));

    // Read embeddings
    for (int i = 0; i < vocab_sz; i++) {
        // Read word
        int word_len;
        file.read(reinterpret_cast<char*>(&word_len), sizeof(word_len));
        std::string word(word_len, '\0');
        file.read(&word[0], word_len);

        // Read embedding
        std::vector<float> emb(dim);
        file.read(reinterpret_cast<char*>(emb.data()), dim * sizeof(float));

        // Store
        int word_id = tokenizer.add_word(word);
        embeddings[word_id] = emb;
    }

    std::cout << "[Embeddings] Loaded " << vocab_sz << " embeddings from " << file_path << "\n";
}

BlockSizeConfig compute_optimal_block_size(int seq_len, int head_dim, size_t l2_cache_size) {
    // Estimate memory per block:
    // Q_block: Bq × head_dim
    // K_block: Bkv × head_dim
    // V_block: Bkv × head_dim
    // O_block: Bq × head_dim
    // Scores: Bq × Bkv
    // Total: (2*Bq + 2*Bkv) * head_dim + Bq * Bkv floats

    BlockSizeConfig config;

    // Try common block sizes
    std::vector<int> candidates = {32, 64, 128, 256};

    for (int bq : candidates) {
        for (int bkv : candidates) {
            size_t mem = (2 * bq + 2 * bkv) * head_dim * sizeof(float);
            mem += bq * bkv * sizeof(float);

            if (mem <= l2_cache_size) {
                config.block_q = bq;
                config.block_kv = bkv;
            }
        }
    }

    // Fallback if nothing fits
    if (config.block_q == 0) {
        config.block_q = 32;
        config.block_kv = 32;
    }

    return config;
}

MemoryStats compute_memory_stats(int batch, int seq_len, int n_heads, int head_dim) {
    MemoryStats stats;

    // Standard attention: O(N²)
    // Stores full attention matrix: [batch, n_heads, seq_len, seq_len]
    stats.standard_attention = batch * n_heads * seq_len * seq_len * sizeof(float);

    // Flash attention: O(N)
    // Only stores: Q, K, V, O + small working buffers
    size_t qkvo = batch * seq_len * n_heads * head_dim * sizeof(float) * 4;
    size_t working = seq_len * 2 * sizeof(float);  // Softmax state
    stats.flash_attention = qkvo + working;

    stats.reduction_factor = (float)stats.standard_attention / stats.flash_attention;

    return stats;
}

void tiled_attention_block(
    const float* Q_block,
    const float* K_block,
    const float* V_block,
    float* O_block,
    float* softmax_state,  // [Bq, 2]: [max_val, sum_exp]
    int Bq,
    int Bkv,
    int head_dim,
    float scale,
    bool causal_mask,
    int q_offset,
    int kv_offset
) {
    // Compute attention scores: S = Q @ K^T
    std::vector<float> scores(Bq * Bkv);

    for (int i = 0; i < Bq; i++) {
        for (int j = 0; j < Bkv; j++) {
            const float* q = Q_block + i * head_dim;
            const float* k = K_block + j * head_dim;

            float score = TensorOps::vec_dot(q, k, head_dim) * scale;

            // Causal masking
            if (causal_mask) {
                int q_pos = q_offset + i;
                int k_pos = kv_offset + j;
                if (k_pos > q_pos) {
                    score = -1e9f;  // Mask future positions
                }
            }

            scores[i * Bkv + j] = score;
        }
    }

    // Online softmax update
    for (int i = 0; i < Bq; i++) {
        float old_max = softmax_state[i * 2];
        float old_sum = softmax_state[i * 2 + 1];

        // Find new max in this block
        float new_max = old_max;
        for (int j = 0; j < Bkv; j++) {
            new_max = std::max(new_max, scores[i * Bkv + j]);
        }

        // Rescale old output and sum if max changed
        float rescale = std::exp(old_max - new_max);
        if (old_max > -1e8f && new_max != old_max) {
            // Rescale previous output
            for (int d = 0; d < head_dim; d++) {
                O_block[i * head_dim + d] *= rescale;
            }
            old_sum *= rescale;
        }

        // Compute exp and accumulate
        float new_sum = old_sum;
        std::vector<float> exp_scores(Bkv);
        for (int j = 0; j < Bkv; j++) {
            exp_scores[j] = std::exp(scores[i * Bkv + j] - new_max);
            new_sum += exp_scores[j];
        }

        // Update output: O += exp(S - max) @ V
        for (int j = 0; j < Bkv; j++) {
            const float* v = V_block + j * head_dim;
            float weight = exp_scores[j];
            for (int d = 0; d < head_dim; d++) {
                O_block[i * head_dim + d] += weight * v[d];
            }
        }

        // Update softmax state
        softmax_state[i * 2] = new_max;
        softmax_state[i * 2 + 1] = new_sum;
    }
}

