std::string decode_html_entities(const std::string& text) {
    std::string result = text;

    // Common HTML entities
    static const struct { const char* entity; const char* replacement; } entities[] = {
        {"&nbsp;", " "}, {"&lt;", "<"}, {"&gt;", ">"}, {"&amp;", "&"},
        {"&quot;", "\""}, {"&#39;", "'"}, {"&apos;", "'"},
        {"&ndash;", "-"}, {"&mdash;", "--"}, {"&hellip;", "..."},
        {"&copy;", "(c)"}, {"&reg;", "(R)"}, {"&trade;", "(TM)"},
        {nullptr, nullptr}
    };

    for (int i = 0; entities[i].entity; i++) {
        size_t pos = 0;
        while ((pos = result.find(entities[i].entity, pos)) != std::string::npos) {
            result.replace(pos, strlen(entities[i].entity), entities[i].replacement);
            pos += strlen(entities[i].replacement);
        }
    }

    // Numeric entities &#NNN; and &#xHH;
    std::regex numeric_entity(R"(&#(\d+);)");
    std::regex hex_entity(R"(&#x([0-9A-Fa-f]+);)");

    result = std::regex_replace(result, numeric_entity, " ");
    result = std::regex_replace(result, hex_entity, " ");

    return result;
}

std::string remove_urls(const std::string& text) {
    std::regex url_pattern(R"((https?://|www\.)[^\s]+)");
    return std::regex_replace(text, url_pattern, "");
}

std::string normalize_whitespace(const std::string& text) {
    std::string result = text;

    // Multiple spaces -> one space
    result = std::regex_replace(result, std::regex(R"([ \t]+)"), " ");

    // Leading/trailing space on each line
    result = std::regex_replace(result, std::regex(R"(\n[ \t]+)"), "\n");
    result = std::regex_replace(result, std::regex(R"([ \t]+\n)"), "\n");

    // Multiple newlines -> max 2 newlines
    result = std::regex_replace(result, std::regex(R"(\n{3,})"), "\n\n");

    // Trim start and end
    size_t start = result.find_first_not_of(" \n\t\r");
    size_t end = result.find_last_not_of(" \n\t\r");

    if (start == std::string::npos) return "";
    return result.substr(start, end - start + 1);
}

std::string extract_text_from_html(const std::string& html) {
    std::string text = html;

    // 1. Remove script tags and content
    text = std::regex_replace(text,
        std::regex(R"(<script[^>]*>.*?</script>)", std::regex::icase), "");

    // 2. Remove style tags and content
    text = std::regex_replace(text,
        std::regex(R"(<style[^>]*>.*?</style>)", std::regex::icase), "");

    // 3. Remove navigation, header, footer, aside
    text = std::regex_replace(text,
        std::regex(R"(<nav[^>]*>.*?</nav>)", std::regex::icase), "");
    text = std::regex_replace(text,
        std::regex(R"(<header[^>]*>.*?</header>)", std::regex::icase), "");
    text = std::regex_replace(text,
        std::regex(R"(<footer[^>]*>.*?</footer>)", std::regex::icase), "");
    text = std::regex_replace(text,
        std::regex(R"(<aside[^>]*>.*?</aside>)", std::regex::icase), "");

    // 4. Remove forms (usually noise)
    text = std::regex_replace(text,
        std::regex(R"(<form[^>]*>.*?</form>)", std::regex::icase), "");

    // 5. Replace block-level closing tags with newlines
    text = std::regex_replace(text,
        std::regex(R"(</(div|p|h[1-6]|li|tr|td|section|article|blockquote)>)",
        std::regex::icase), "\n");

    // 6. Replace <br> with newline
    text = std::regex_replace(text,
        std::regex(R"(<br\s*/?>)", std::regex::icase), "\n");

    // 7. Remove ALL remaining HTML tags
    text = std::regex_replace(text, std::regex(R"(<[^>]*>)"), "");

    // 8. Decode HTML entities
    text = decode_html_entities(text);

    // 9. Remove URLs
    text = remove_urls(text);

    // 10. Normalize whitespace
    text = normalize_whitespace(text);

    return text;
}

static void assign_lengths(const std::vector<HNode>& nodes, int idx,
                            int depth, uint8_t lengths[HUFF_SYMBOLS]) {
    if (idx < 0) return;
    const HNode& n = nodes[idx];
    if (n.sym >= 0) {
        // leaf — store depth (may exceed 15 for unbalanced trees)
        lengths[n.sym] = (uint8_t)std::min(depth, 255);
        return;
    }
    assign_lengths(nodes, n.left,  depth + 1, lengths);
    assign_lengths(nodes, n.right, depth + 1, lengths);
}

static void limit_lengths(uint8_t lengths[HUFF_SYMBOLS], int max_bits) {
    bool any_over = false;
    for (int s = 0; s < HUFF_SYMBOLS; ++s) {
        if (lengths[s] > (uint8_t)max_bits) {
            lengths[s] = (uint8_t)max_bits;
            any_over = true;
        }
    }
    if (!any_over) return;

    // Fix Kraft inequality: excess = kraft - 2^max_bits.
    // When we clamp L symbols from depth d > max_bits to max_bits,
    // we add too many "slots". We fix by repeatedly finding the
    // symbol with the current shortest length (most slots) and
    // incrementing it by 1 (halves its slot count).
    for (int iter = 0; iter < 10000; ++iter) {
        // Compute current Kraft sum
        long long kraft = 0;
        for (int s = 0; s < HUFF_SYMBOLS; ++s)
            if (lengths[s] > 0)
                kraft += (1LL << (max_bits - lengths[s]));

        long long target = (1LL << max_bits);
        if (kraft <= target) break;  // done (under or equal is fine — unused slots OK)

        // Too many slots: find shortest-length active symbol and increase it
        int min_len = max_bits + 1;
        for (int s = 0; s < HUFF_SYMBOLS; ++s)
            if (lengths[s] > 0 && lengths[s] < min_len)
                min_len = lengths[s];

        if (min_len > max_bits) break;  // can't increase further

        // Increase the LAST symbol with min_len (least likely to affect
        // high-frequency symbols)
        for (int s = HUFF_SYMBOLS - 1; s >= 0; --s) {
            if (lengths[s] == (uint8_t)min_len) {
                lengths[s]++;
                break;
            }
        }
    }
}

static void build_canonical_codes(HuffTable& table) {
    // Count how many symbols have each bit length
    int bl_count[16] = {};
    for (int s = 0; s < HUFF_SYMBOLS; ++s)
        if (table.code_len[s] > 0)
            bl_count[table.code_len[s]]++;

    // Find starting code for each bit length
    uint32_t next_code[16] = {};
    uint32_t code = 0;
    for (int bits = 1; bits <= 15; ++bits) {
        code = (code + bl_count[bits - 1]) << 1;
        next_code[bits] = code;
    }

    // Assign codes
    for (int s = 0; s < HUFF_SYMBOLS; ++s) {
        int len = table.code_len[s];
        if (len > 0) {
            table.code[s] = next_code[len]++;
        }
    }
}

HuffTable huffman_build(const uint32_t freq[HUFF_SYMBOLS]) {
    HuffTable table;
    memset(table.code_len, 0, sizeof(table.code_len));
    memset(table.code,     0, sizeof(table.code));

    // Count active symbols
    int active = 0;
    for (int s = 0; s < HUFF_SYMBOLS; ++s)
        if (freq[s] > 0) ++active;

    if (active == 0) return table;

    // Edge case: only one unique symbol — give it length 1
    if (active == 1) {
        for (int s = 0; s < HUFF_SYMBOLS; ++s) {
            if (freq[s] > 0) {
                table.code_len[s] = 1;
                table.code[s]     = 0;
                return table;
            }
        }
    }

    // Build node pool
    std::vector<HNode> nodes;
    nodes.reserve(HUFF_SYMBOLS * 2);
    for (int s = 0; s < HUFF_SYMBOLS; ++s) {
        if (freq[s] > 0)
            nodes.push_back({freq[s], s, -1, -1});
    }

    // Min-heap: (freq, node_index)
    auto cmp = [](std::pair<uint32_t,int> a, std::pair<uint32_t,int> b) {
        return a.first > b.first;  // min-heap
    };
    std::priority_queue<std::pair<uint32_t,int>,
                        std::vector<std::pair<uint32_t,int>>,
                        decltype(cmp)> pq(cmp);

    for (int i = 0; i < (int)nodes.size(); ++i)
        pq.push({nodes[i].freq, i});

    // Merge until one node remains (the root)
    while (pq.size() > 1) {
        auto [f1, i1] = pq.top(); pq.pop();
        auto [f2, i2] = pq.top(); pq.pop();
        int merged_idx = (int)nodes.size();
        nodes.push_back({f1 + f2, -1, i1, i2});
        pq.push({f1 + f2, merged_idx});
    }

    int root = pq.top().second;

    // Walk tree to assign lengths
    uint8_t lengths[HUFF_SYMBOLS] = {};
    assign_lengths(nodes, root, 0, lengths);

    // Limit to 15 bits so canonical codes fit in uint32_t without overflow
    limit_lengths(lengths, 15);

    memcpy(table.code_len, lengths, sizeof(lengths));

    // Build canonical codes from lengths
    build_canonical_codes(table);

    return table;
}

void huffman_encode(const uint8_t* data, size_t len,
                    const HuffTable& table, BitWriter& bw) {
    for (size_t i = 0; i < len; ++i) {
        uint8_t sym = data[i];
        int     clen = table.code_len[sym];
        if (clen == 0)
            throw std::runtime_error("huffman_encode: symbol not in table");
        bw.write_bits(table.code[sym], clen);
    }
}

std::vector<uint8_t> huffman_decode(BitReader& br, const HuffTable& table,
                                    size_t num_symbols) {
    std::vector<uint8_t> out;
    out.reserve(num_symbols);

    for (size_t i = 0; i < num_symbols; ++i) {
        uint32_t code = 0;
        int      len  = 0;
        bool     found = false;

        while (len < 16) {
            code = (code << 1) | (uint32_t)br.read_bit();
            ++len;
            // Check if this matches any symbol with this length
            for (int s = 0; s < HUFF_SYMBOLS; ++s) {
                if (table.code_len[s] == len && table.code[s] == code) {
                    out.push_back((uint8_t)s);
                    found = true;
                    break;
                }
            }
            if (found) break;
        }

        if (!found)
            throw std::runtime_error("huffman_decode: invalid code in bitstream");
    }
    return out;
}

void huffman_write_lengths(const HuffTable& table, std::vector<uint8_t>& out) {
    for (int s = 0; s < HUFF_SYMBOLS; ++s)
        out.push_back(table.code_len[s]);
}

HuffTable huffman_read_lengths(const uint8_t lengths[HUFF_SYMBOLS]) {
    HuffTable table;
    memcpy(table.code_len, lengths, HUFF_SYMBOLS);
    memset(table.code, 0, sizeof(table.code));
    build_canonical_codes(table);
    return table;
}

void run_learn(const std::string& source) {
    std::cout << "[LEARN] Fetching: " << source << "\n";

    // Ensure knowledge directory exists
    fs::create_directories("brain/knowledge");

    // Check if source is a URL or file path
    bool is_url = (source.find("http://") == 0 || source.find("https://") == 0);

    std::string text_content;
    std::string source_name;

    if (is_url) {
        // Fetch from internet
        HttpResponse resp = fetch_url(source);

        if (resp.status_code != 200) {
            std::cerr << "[LEARN] Failed to fetch URL (status " << resp.status_code << "): " << source << "\n";
            return;
        }

        std::cout << "[LEARN] Downloaded " << resp.body.size() << " bytes\n";

        // Extract clean text from HTML
        text_content = extract_text_from_html(resp.body);

        // Create a safe filename from URL
        source_name = source;
        // Remove protocol
        size_t proto_end = source_name.find("://");
        if (proto_end != std::string::npos) {
            source_name = source_name.substr(proto_end + 3);
        }
        // Replace unsafe chars
        for (char& c : source_name) {
            if (c == '/' || c == '\\' || c == ':' || c == '?' || c == '&' ||
                c == '=' || c == '#' || c == '%' || c == ' ') {
                c = '_';
            }
        }
        // Limit filename length
        if (source_name.size() > 100) {
            source_name = source_name.substr(0, 100);
        }

    } else {
        // Read from local file
        std::ifstream file(source);
        if (!file) {
            std::cerr << "[LEARN] Cannot open file: " << source << "\n";
            return;
        }

        text_content = std::string(
            (std::istreambuf_iterator<char>(file)),
            std::istreambuf_iterator<char>()
        );

        source_name = fs::path(source).stem().string();
    }

    // Filter out very short content
    if (text_content.size() < 50) {
        std::cerr << "[LEARN] Content too short (" << text_content.size() << " chars), skipping\n";
        return;
    }

    // Save to knowledge base
    std::string output_file = "brain/knowledge/" + source_name + ".txt";
    std::ofstream out(output_file);
    if (out) {
        out << text_content;
        out.close();
        std::cout << "[LEARN] Saved " << text_content.size() << " chars to " << output_file << "\n";
    }

    // Also append to a combined training corpus for future retraining
    std::string corpus_file = "brain/self_learning/learned_corpus.txt";
    std::ofstream corpus(corpus_file, std::ios::app);
    if (corpus) {
        // Write each sentence as a line
        std::istringstream iss(text_content);
        std::string line;
        int lines_added = 0;
        while (std::getline(iss, line)) {
            // Skip very short lines
            if (line.size() > 20) {
                corpus << line << "\n";
                lines_added++;
            }
        }
        corpus.close();
        std::cout << "[LEARN] Added " << lines_added << " lines to training corpus\n";
    }

    std::cout << "[LEARN] ✅ Learning complete from: " << source << "\n";
}

