float CrossEntropyLoss::forward(const std::vector<float>& logits, int target) {
    // Compute softmax probabilities
    probs_ = Softmax::stable_softmax(logits);

    // Compute negative log likelihood
    float loss = -std::log(probs_[target] + 1e-10f);  // Add epsilon for numerical stability

    // Apply label smoothing if enabled
    if (label_smoothing_ > 0.0f) {
        int vocab_size = logits.size();
        float smooth_loss = 0.0f;
        for (float prob : probs_) {
            smooth_loss -= std::log(prob + 1e-10f);
        }
        smooth_loss /= vocab_size;

        loss = (1.0f - label_smoothing_) * loss + label_smoothing_ * smooth_loss;
    }

    return loss;
}

std::vector<float> CrossEntropyLoss::backward(const std::vector<float>& logits, int target) {
    // Gradient of cross-entropy w.r.t. logits
    // grad[i] = prob[i] - (i == target ? 1 : 0)
    std::vector<float> grad(logits.size());

    for (size_t i = 0; i < logits.size(); i++) {
        grad[i] = probs_[i];
        if (static_cast<int>(i) == target) {
            grad[i] -= 1.0f;
        }

        // Apply label smoothing
        if (label_smoothing_ > 0.0f) {
            float smooth_target = label_smoothing_ / logits.size();
            grad[i] = (1.0f - label_smoothing_) * grad[i] + smooth_target;
        }
    }

    return grad;
}

float CrossEntropyLoss::forward_backward(const std::vector<float>& logits, int target, std::vector<float>& grad_out) {
    float loss = forward(logits, target);
    grad_out = backward(logits, target);
    return loss;
}

std::vector<float> forward(const std::vector<float>& logits) {
    return stable_softmax(logits);
}

std::vector<float> stable_softmax(const std::vector<float>& logits) {
    // Find max for numerical stability
    float max_logit = *std::max_element(logits.begin(), logits.end());

    // Compute exp(logits - max)
    std::vector<float> exp_logits(logits.size());
    float sum_exp = 0.0f;

    for (size_t i = 0; i < logits.size(); i++) {
        exp_logits[i] = std::exp(logits[i] - max_logit);
        sum_exp += exp_logits[i];
    }

    // Normalize
    for (float& val : exp_logits) {
        val /= sum_exp;
    }

    return exp_logits;
}

std::vector<float> backward(const std::vector<float>& probs, const std::vector<float>& grad_probs) {
    // Jacobian of softmax is: J[i,j] = probs[i] * (delta[i,j] - probs[j])
    // For cross-entropy, this simplifies to: grad_logits[i] = probs[i] - targets[i]

    int n = probs.size();
    std::vector<float> grad_logits(n, 0.0f);

    // Compute dot product: sum(probs * grad_probs)
    float dot = 0.0f;
    for (int i = 0; i < n; i++) {
        dot += probs[i] * grad_probs[i];
    }

    // Compute gradient
    for (int i = 0; i < n; i++) {
        grad_logits[i] = probs[i] * (grad_probs[i] - dot);
    }

    return grad_logits;
}

float MSELoss::forward(const std::vector<float>& predictions, const std::vector<float>& targets) {
    float sum_sq_error = 0.0f;

    for (size_t i = 0; i < predictions.size(); i++) {
        float diff = predictions[i] - targets[i];
        sum_sq_error += diff * diff;
    }

    if (reduce_mean_) {
        return sum_sq_error / predictions.size();
    } else {
        return sum_sq_error;
    }
}

std::vector<float> MSELoss::backward(const std::vector<float>& predictions, const std::vector<float>& targets) {
    std::vector<float> grad(predictions.size());

    float scale = reduce_mean_ ? (2.0f / predictions.size()) : 2.0f;

    for (size_t i = 0; i < predictions.size(); i++) {
        grad[i] = scale * (predictions[i] - targets[i]);
    }

    return grad;
}

float ContrastiveLoss::forward(float positive_sim, const std::vector<float>& negative_sims) {
    // Contrastive loss: -log(exp(pos) / (exp(pos) + sum(exp(neg))))
    // This encourages positive_sim to be large and negative_sims to be small

    float exp_pos = std::exp(positive_sim);
    float sum_exp_neg = 0.0f;

    for (float neg_sim : negative_sims) {
        sum_exp_neg += std::exp(neg_sim);
    }

    float loss = -std::log(exp_pos / (exp_pos + sum_exp_neg + 1e-10f));
    return loss;
}

void ContrastiveLoss::backward(float positive_sim, const std::vector<float>& negative_sims,
                                float& grad_positive, std::vector<float>& grad_negatives) {
    float exp_pos = std::exp(positive_sim);
    float sum_exp_neg = 0.0f;

    for (float neg_sim : negative_sims) {
        sum_exp_neg += std::exp(neg_sim);
    }

    float denominator = exp_pos + sum_exp_neg;

    // Gradient w.r.t. positive similarity
    grad_positive = -1.0f + (exp_pos / denominator);

    // Gradient w.r.t. negative similarities
    grad_negatives.resize(negative_sims.size());
    for (size_t i = 0; i < negative_sims.size(); i++) {
        float exp_neg = std::exp(negative_sims[i]);
        grad_negatives[i] = exp_neg / denominator;
    }
}

float log_sum_exp(const std::vector<float>& values) {
    if (values.empty()) return 0.0f;

    float max_val = *std::max_element(values.begin(), values.end());
    float sum_exp = 0.0f;

    for (float val : values) {
        sum_exp += std::exp(val - max_val);
    }

    return max_val + std::log(sum_exp);
}

float nll_loss(const std::vector<float>& log_probs, int target) {
    return -log_probs[target];
}

std::vector<float> smooth_labels(int vocab_size, int target, float smoothing) {
    std::vector<float> labels(vocab_size, smoothing / vocab_size);
    labels[target] += (1.0f - smoothing);
    return labels;
}

float perplexity(float cross_entropy_loss) {
    return std::exp(cross_entropy_loss);
}

static inline uint32_t hash3(const uint8_t* p) {
    return ((uint32_t)p[0]) | ((uint32_t)p[1] << 8) | ((uint32_t)p[2] << 16);
}

static inline int match_length(const uint8_t* a, const uint8_t* b, int max_len) {
    int len = 0;
#ifdef __SSE2__
    while (len + 16 <= max_len) {
        __m128i va   = _mm_loadu_si128((const __m128i*)(a + len));
        __m128i vb   = _mm_loadu_si128((const __m128i*)(b + len));
        uint32_t diff = (~(uint32_t)_mm_movemask_epi8(_mm_cmpeq_epi8(va, vb))) & 0xFFFFu;
        if (diff) return len + __builtin_ctz(diff);
        len += 16;
    }
#endif
    while (len < max_len && a[len] == b[len]) ++len;
    return len;
}

std::vector<LZToken> lz77_encode(
    const uint8_t* data, size_t n,
    std::function<void(size_t, size_t)> progress_cb,
    bool use_lazy)
{
    std::vector<LZToken> tokens;
    tokens.reserve(n / 2);

    // hash_table: 3-byte hash -> sorted list of positions in data
    // We store up to 8 candidates per key to keep memory sane on large files
    static constexpr int MAX_CHAIN = 8;
    std::unordered_map<uint32_t, std::vector<uint32_t>> ht;
    ht.reserve(1 << 16);

    auto add_pos = [&](size_t pos) {
        if (pos + 3 > n) return;
        uint32_t key = hash3(data + pos);
        auto& chain  = ht[key];
        if (chain.size() < MAX_CHAIN)
            chain.push_back((uint32_t)pos);
        else {
            // Replace oldest (index 0) — sliding window eviction
            chain.erase(chain.begin());
            chain.push_back((uint32_t)pos);
        }
    };

    // -------------------------------------------------------------------------
    // find_best_match: search hash table at position pos, return best
    // (length, distance) pair. Returns length=0 if no match >= LZ_MIN_MATCH.
    // -------------------------------------------------------------------------
    auto find_best_match = [&](size_t pos, int& out_len, int& out_dist) {
        out_len  = 0;
        out_dist = 0;
        if (pos + LZ_MIN_MATCH > n) return;

        uint32_t key       = hash3(data + pos);
        auto     it        = ht.find(key);
        if (it == ht.end()) return;

        size_t win_start = (pos >= (size_t)LZ_WINDOW) ? pos - LZ_WINDOW : 0;
        const auto& chain = it->second;

        for (int c = (int)chain.size() - 1; c >= 0; --c) {
            size_t cand = chain[c];
            if (cand < win_start) break;
            if (cand >= pos) continue;

            int max_len = (int)std::min((size_t)LZ_MAX_MATCH, n - pos);
            int length  = match_length(data + cand, data + pos, max_len);

            if (length > out_len) {
                out_len  = length;
                out_dist = (int)(pos - cand);
                if (out_len == LZ_MAX_MATCH) break;
            }
        }
    };

    // -------------------------------------------------------------------------
    // Lazy matching main loop (zlib level 4+ strategy):
    //   At position i, find best match (prev_len, prev_dist).
    //   Peek at i+1. If that match is strictly longer, emit literal at i
    //   and take the better match at i+1 instead.
    //   This gives 1-3% better compression vs pure greedy at ~25% speed cost.
    // -------------------------------------------------------------------------
    size_t i        = 0;
    size_t next_rpt = 65536;

    int prev_len  = 0;
    int prev_dist = 0;

    // Prime: find match at position 0
    if (n > 0) find_best_match(0, prev_len, prev_dist);

    while (i < n) {
        // Progress reporting
        if (progress_cb && i >= next_rpt) {
            progress_cb(i, n);
            next_rpt = i + 65536;
        }

        // Near end of input — no room for lazy lookahead, emit literal
        if (i + LZ_MIN_MATCH > n) {
            LZToken t; t.is_match = false; t.byte = data[i];
            t.dist = 0; t.len = 0;
            tokens.push_back(t);
            add_pos(i);
            ++i;
            prev_len = 0;
            continue;
        }

        // Lazy check thresholds (zlib-inspired):
        //   NICE_LENGTH: skip lazy if prev_len already this long (not worth it)
        //   LAZY_MIN:    only do lazy if prev_len <= this (minimal matches only)
        // These together mean: only try lazy when the current match is short
        // (3-8 bytes) and not already at the "nice" threshold.
        static constexpr int NICE_LENGTH = 32;
        static constexpr int LAZY_MIN    = 8;

        if (prev_len < LZ_MIN_MATCH) {
            // No usable match at i — emit literal, find match at i+1
            LZToken t; t.is_match = false; t.byte = data[i];
            t.dist = 0; t.len = 0;
            tokens.push_back(t);
            add_pos(i);
            ++i;
            find_best_match(i, prev_len, prev_dist);
        } else {
            // We have a match at i. Check i+1 for a better one (lazy step),
            // but only within the useful range [LZ_MIN_MATCH, LAZY_MIN].
            int next_len = 0, next_dist = 0;
            if (use_lazy && prev_len <= LAZY_MIN && prev_len < NICE_LENGTH && i + 1 < n)
                find_best_match(i + 1, next_len, next_dist);

            if (next_len > prev_len) {
                // Better match one byte ahead — emit literal at i, defer
                LZToken t; t.is_match = false; t.byte = data[i];
                t.dist = 0; t.len = 0;
                tokens.push_back(t);
                add_pos(i);
                ++i;
                prev_len  = next_len;
                prev_dist = next_dist;
            } else {
                // Take the match at i
                LZToken t;
                t.is_match = true;
                t.byte     = 0;
                t.dist     = (uint16_t)prev_dist;
                t.len      = (uint8_t)(prev_len - LZ_MIN_MATCH);
                tokens.push_back(t);
                for (int j = 0; j < prev_len; ++j)
                    add_pos(i + j);
                i += prev_len;
                // Find match at new position
                find_best_match(i, prev_len, prev_dist);
            }
        }
    }

    if (progress_cb) progress_cb(n, n);
    return tokens;
}

std::vector<uint8_t> lz77_decode(const LZToken* tokens, size_t count) {
    std::vector<uint8_t> out;
    out.reserve(count * 4);   // rough estimate

    for (size_t i = 0; i < count; ++i) {
        const LZToken& t = tokens[i];
        if (!t.is_match) {
            out.push_back(t.byte);
        } else {
            int actual_len  = t.len + LZ_MIN_MATCH;
            size_t start    = out.size();
            if (t.dist > start)
                throw std::runtime_error("lz77_decode: invalid distance");
            size_t src = start - t.dist;
            // Copy byte by byte — handles overlapping matches correctly
            for (int j = 0; j < actual_len; ++j)
                out.push_back(out[src + j]);
        }
    }
    return out;
}

std::vector<uint8_t> lz77_serialize(const LZToken* tokens, size_t count) {
    std::vector<uint8_t> out;
    out.reserve(count * 3);

    for (size_t i = 0; i < count; ++i) {
        const LZToken& t = tokens[i];
        if (!t.is_match) {
            out.push_back(0x00);
            out.push_back(t.byte);
        } else {
            out.push_back(0x01);
            out.push_back((t.dist >> 8) & 0xFF);
            out.push_back(t.dist & 0xFF);
            out.push_back(t.len);
        }
    }
    return out;
}

std::vector<LZToken> lz77_deserialize(const uint8_t* data, size_t len) {
    std::vector<LZToken> tokens;
    size_t i = 0;
    while (i < len) {
        uint8_t flag = data[i++];
        if (flag == 0x00) {
            if (i >= len)
                throw std::runtime_error("lz77_deserialize: truncated literal");
            LZToken t;
            t.is_match = false;
            t.byte     = data[i++];
            t.dist     = 0;
            t.len      = 0;
            tokens.push_back(t);
        } else if (flag == 0x01) {
            if (i + 3 > len)
                throw std::runtime_error("lz77_deserialize: truncated match");
            LZToken t;
            t.is_match = true;
            t.byte     = 0;
            t.dist     = ((uint16_t)data[i] << 8) | data[i+1];
            t.len      = data[i+2];
            i += 3;
            tokens.push_back(t);
        } else {
            throw std::runtime_error("lz77_deserialize: unknown flag byte");
        }
    }
    return tokens;
}

static void print_progress(const char* stage, size_t done, size_t total, int models = 0) {
    if (total == 0) return;

    auto now     = std::chrono::steady_clock::now();
    double elapsed = std::chrono::duration<double>(now - g_start).count();
    double pct   = (double)done / (double)total;
    int    filled = (int)(35.0 * pct);

    double eta = (elapsed > 0 && pct > 0.001)
                 ? elapsed / pct * (1.0 - pct)
                 : -1.0;

    char eta_str[16];
    if (eta < 0)         snprintf(eta_str, sizeof(eta_str), "  ??s");
    else if (eta < 1.0)  snprintf(eta_str, sizeof(eta_str), " <1s");
    else                 snprintf(eta_str, sizeof(eta_str), "%4.0fs", eta);

    double mb_done  = done  / (1024.0 * 1024.0);
    double mb_total = total / (1024.0 * 1024.0);

    char bar[36];
    for (int i = 0; i < 35; ++i)
        bar[i] = (i < filled) ? '#' : '.';
    bar[35] = '\0';

    // Pad stage label to 7 chars
    char slabel[8];
    snprintf(slabel, sizeof(slabel), "%-7s", stage);

    double mb_per_sec = (elapsed > 0) ? (mb_done / elapsed) : 0.0;

    if (models > 0) {
        printf("\r  [%s] %s  %5.1f%%  %5.1f/%5.1f MB  ETA %s  [%.2f MB/s] Models: %4d   ",
               bar, slabel, pct * 100.0, mb_done, mb_total, eta_str, mb_per_sec, models);
    } else {
        printf("\r  [%s] %s  %5.1f%%  %5.1f/%5.1f MB  ETA %s  [%.2f MB/s]               ",
               bar, slabel, pct * 100.0, mb_done, mb_total, eta_str, mb_per_sec);
    }
    fflush(stdout);

    if (done >= total) {
        printf("\n");
        fflush(stdout);
    }
}

static long long file_size(const std::string& path) {
    std::ifstream f(path, std::ios::binary | std::ios::ate);
    return f ? (long long)f.tellg() : -1;
}

static bool ends_with(const std::string& s, const std::string& suffix) {
    return s.size() >= suffix.size() &&
           s.compare(s.size() - suffix.size(), suffix.size(), suffix) == 0;
}

static void cmd_compress(const std::string& input, const std::string& output,
                         bool verbose, CompressMode mode) {
    long long in_size = file_size(input);
    if (in_size < 0) {
        fprintf(stderr, "Error: cannot open '%s'\n", input.c_str());
        exit(1);
    }

    const char* mode_label = (mode == CompressMode::CMIX) ? "CMIX (--cmix)"
                           : (mode == CompressMode::ULTRA) ? "PPM (--ultra)"
                           : (mode == CompressMode::BEST)  ? "BWT (--best)"
                           : "LZ77+delta (default)";
    printf("\n  Input   : %s\n",   input.c_str());
    printf("  Output  : %s\n",     output.c_str());
    printf("  Mode    : %s\n",     mode_label);
    printf("  Original: %.2f MB (%lld bytes)\n", in_size / (1024.0*1024.0), in_size);

    // Show thread count for multi-threaded modes
    if (mode == CompressMode::BEST || mode == CompressMode::ULTRA || mode == CompressMode::CMIX) {
        unsigned int num_threads = std::thread::hardware_concurrency();
        if (num_threads == 0) num_threads = 4;
        printf("  Threads : %u (multi-threaded compression)\n", num_threads);
    }
    printf("\n");

    g_start = std::chrono::steady_clock::now();

    bool show_bar = true;
    ProgressCb cb = nullptr;
    if (show_bar) {
        cb = [](const char* stage, size_t done, size_t total, int models) {
            if (strcmp(stage, "write") != 0)   // skip the write stage
                print_progress(stage, done, total, models);
        };
    }

    int rc = compress_file(input, output, cb, mode);
    if (rc != 0) { fprintf(stderr, "Compression failed.\n"); exit(1); }

    double elapsed = std::chrono::duration<double>(
        std::chrono::steady_clock::now() - g_start).count();

    long long out_size = file_size(output);
    double ratio = (in_size > 0) ? (double)out_size / (double)in_size : 1.0;

    printf("  Compressed : %.2f MB (%lld bytes)\n", out_size/(1024.0*1024.0), out_size);
    printf("  Ratio      : %.4f  (%.1f%% saved)\n", ratio, (1.0 - ratio)*100.0);
    printf("  Time       : %.2f s\n\n", elapsed);
}

static void cmd_decompress(const std::string& input, const std::string& output,
                            bool verbose) {
    long long in_size = file_size(input);
    if (in_size < 0) {
        fprintf(stderr, "Error: cannot open '%s'\n", input.c_str());
        exit(1);
    }

    printf("\n  Input : %s\n", input.c_str());
    printf("  Output: %s\n\n", output.c_str());

    g_start = std::chrono::steady_clock::now();

    bool show_bar = (in_size > 100 * 1024);
    ProgressCb cb = nullptr;
    if (show_bar) {
        cb = [](const char* stage, size_t done, size_t total, int models) {
            if (strcmp(stage, "decompress") == 0)
                print_progress(stage, done, total, models);
        };
    }

    int rc = decompress_file(input, output, cb);
    if (rc != 0) { fprintf(stderr, "Decompression failed.\n"); exit(1); }

    double elapsed = std::chrono::duration<double>(
        std::chrono::steady_clock::now() - g_start).count();

    long long out_size = file_size(output);
    printf("  Recovered  : %.2f MB (%lld bytes)\n", out_size/(1024.0*1024.0), out_size);
    printf("  Time       : %.2f s\n", elapsed);
    printf("  SHA-256    : OK (lossless verified)\n\n");
}

static void cmd_benchmark(const std::string& input) {
    long long in_size = file_size(input);
    if (in_size < 0) {
        fprintf(stderr, "Error: cannot open '%s'\n", input.c_str());
        exit(1);
    }

    std::string tmp_c  = input + ".bench.aiz";
    std::string tmp_d  = input + ".bench.recovered";

    printf("\n  Benchmarking: %s  (%.2f MB)\n\n", input.c_str(), in_size/(1024.0*1024.0));

    // Compress
    g_start = std::chrono::steady_clock::now();
    compress_file(input, tmp_c, nullptr, CompressMode::DEFAULT);
    double c_time = std::chrono::duration<double>(
        std::chrono::steady_clock::now() - g_start).count();

    // Decompress
    g_start = std::chrono::steady_clock::now();
    decompress_file(tmp_c, tmp_d, nullptr);
    double d_time = std::chrono::duration<double>(
        std::chrono::steady_clock::now() - g_start).count();

    long long c_size = file_size(tmp_c);
    double ratio = (double)c_size / (double)in_size;
    double c_speed = (in_size / (1024.0*1024.0)) / c_time;
    double d_speed = (in_size / (1024.0*1024.0)) / d_time;

    printf("  %-20s %10s %8s %8s %10s\n", "Stage", "Size", "Ratio", "Saved", "Speed");
    printf("  %-20s %10s %8s %8s %10s\n", "--------------------",
           "----------", "--------", "--------", "----------");
    printf("  %-20s %7.2f MB %8.4f %7.1f%%  %6.1f MB/s\n",
           "Compress (C++)", c_size/(1024.0*1024.0), ratio, (1.0-ratio)*100.0, c_speed);
    printf("  %-20s %7.2f MB %8s %8s  %6.1f MB/s\n",
           "Decompress (C++)", in_size/(1024.0*1024.0), "-", "-", d_speed);
    printf("\n");

    // Clean up temp files
    remove(tmp_c.c_str());
    remove(tmp_d.c_str());
}

int main_compress(int argc, char* argv[]) {
    if (argc < 2) { usage(); return 1; }

    std::string cmd = argv[1];
    std::string input, output;
    bool verbose       = false;
    CompressMode mode  = CompressMode::DEFAULT;

    // Parse remaining args
    for (int i = 2; i < argc; ++i) {
        std::string a = argv[i];
        if (a == "-o" && i + 1 < argc) {
            output = argv[++i];
        } else if (a == "-v") {
            verbose = true;
        } else if (a == "--best") {
            mode = CompressMode::BEST;
        } else if (a == "--ultra") {
            mode = CompressMode::ULTRA;
        } else if (a == "--cmix") {
            mode = CompressMode::CMIX;
        } else if (a[0] != '-') {
            if (input.empty()) input = a;
            else               output = a;  // positional output
        } else {
            fprintf(stderr, "Unknown option: %s\n", a.c_str());
            return 1;
        }
    }

    if (cmd == "compress") {
        if (input.empty()) { fprintf(stderr, "Error: missing input file\n"); return 1; }
        if (output.empty()) output = input + ".aiz";
        cmd_compress(input, output, verbose, mode);

    } else if (cmd == "decompress") {
        if (input.empty()) { fprintf(stderr, "Error: missing input file\n"); return 1; }
        if (output.empty()) {
            output = ends_with(input, ".aiz")
                     ? input.substr(0, input.size() - 6) + ".recovered"
                     : input + ".recovered";
        }
        cmd_decompress(input, output, verbose);

    } else if (cmd == "benchmark") {
        if (input.empty()) { fprintf(stderr, "Error: missing input file\n"); return 1; }
        cmd_benchmark(input);

    } else {
        fprintf(stderr, "Unknown command: %s\n", cmd.c_str());
        usage();
        return 1;
    }

    return 0;
}

int main(int argc, char* argv[]) {
    return main_compress(argc, argv);
}

