bool has_overflow(const float* gradients, int size) {
    for (int i = 0; i < size; i++) {
        if (std::isinf(gradients[i]) || std::isnan(gradients[i])) {
            return true;
        }
    }
    return false;
}

std::vector<std::string> load_corpus(const std::string& filename) {
    std::vector<std::string> lines;
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "❌ Failed to open corpus: " << filename << "\n";
        return lines;
    }

    std::string line;
    while (std::getline(file, line)) {
        if (!line.empty()) {
            lines.push_back(line);
        }
    }

    std::cerr << "✅ Loaded " << lines.size() << " lines from corpus\n";
    return lines;
}

