int AdamOptimizer::get_param_group_id(int size) {
    // Find existing parameter group with this size
    for (int i = 0; i < num_param_groups_; i++) {
        if (param_sizes_[i] == size) {
            return i;
        }
    }

    // Create new parameter group
    param_sizes_.push_back(size);
    m_.push_back(std::vector<float>(size, 0.0f));
    v_.push_back(std::vector<float>(size, 0.0f));
    return num_param_groups_++;
}

void AdamOptimizer::update(float* param, const float* grad, int size) {
    // Get or create parameter group
    int group_id = get_param_group_id(size);
    auto& m = m_[group_id];
    auto& v = v_[group_id];

    // Increment step counter
    step_++;

    // Bias correction factors
    float bias_correction1 = 1.0f - std::pow(beta1_, static_cast<float>(step_));
    float bias_correction2 = 1.0f - std::pow(beta2_, static_cast<float>(step_));

    // Update parameters
    for (int i = 0; i < size; i++) {
        float g = grad[i];

        // L2 regularization (weight decay)
        if (weight_decay_ > 0.0f) {
            g += weight_decay_ * param[i];
        }

        // Update biased first moment estimate (momentum)
        m[i] = beta1_ * m[i] + (1.0f - beta1_) * g;

        // Update biased second moment estimate (RMSProp)
        v[i] = beta2_ * v[i] + (1.0f - beta2_) * g * g;

        // Compute bias-corrected first moment
        float m_hat = m[i] / bias_correction1;

        // Compute bias-corrected second moment
        float v_hat = v[i] / bias_correction2;

        // Update parameter
        param[i] -= learning_rate_ * m_hat / (std::sqrt(v_hat) + epsilon_);
    }
}

void AdamOptimizer::update_with_clipping(float* param, const float* grad, int size, float max_norm) {
    // Clip gradients first
    std::vector<float> clipped_grad(size);
    std::memcpy(clipped_grad.data(), grad, size * sizeof(float));

    float norm = GradientUtils::clip_grad_norm(clipped_grad.data(), size, max_norm);

    // Log if gradients were clipped (disabled for speed - was slowing training 10x)
    // if (norm > max_norm) {
    //     std::cerr << "[OPTIMIZER] Clipped gradients: norm=" << norm << " -> " << max_norm << "\n";
    // }

    // Update with clipped gradients
    update(param, clipped_grad.data(), size);
}

void AdamOptimizer::reset() {
    step_ = 0;
    for (auto& m_group : m_) {
        std::fill(m_group.begin(), m_group.end(), 0.0f);
    }
    for (auto& v_group : v_) {
        std::fill(v_group.begin(), v_group.end(), 0.0f);
    }
}

float clip_grad_norm(float* grad, int size, float max_norm) {
    // Compute gradient norm
    float norm = grad_norm(grad, size);

    // Clip if necessary
    if (norm > max_norm) {
        float scale = max_norm / (norm + 1e-6f);
        for (int i = 0; i < size; i++) {
            grad[i] *= scale;
        }
    }

    return norm;
}

void clip_grad_value(float* grad, int size, float clip_value) {
    for (int i = 0; i < size; i++) {
        grad[i] = std::max(-clip_value, std::min(clip_value, grad[i]));
    }
}

float grad_norm(const float* grad, int size) {
    float sum_sq = 0.0f;
    for (int i = 0; i < size; i++) {
        sum_sq += grad[i] * grad[i];
    }
    return std::sqrt(sum_sq);
}

void zero_grad(float* grad, int size) {
    std::memset(grad, 0, size * sizeof(float));
}

void save_mixer_weights(const Mixer& mixer, const std::string& path) {
    std::ofstream f(path, std::ios::binary);
    if (!f) return;  // Silently fail if can't save

    // Write global weights
    uint32_t n_global = mixer.global_weights.size();
    f.write((char*)&n_global, sizeof(n_global));
    f.write((char*)mixer.global_weights.data(), n_global * sizeof(float));

    // Write niche weights
    uint32_t n_niche = mixer.niche_weights.size();
    f.write((char*)&n_niche, sizeof(n_niche));
    f.write((char*)mixer.niche_weights.data(), n_niche * sizeof(float));
}

bool load_mixer_weights(Mixer& mixer, const std::string& path) {
    std::ifstream f(path, std::ios::binary);
    if (!f) return false;  // File doesn't exist yet

    // Read global weights
    uint32_t n_global;
    f.read((char*)&n_global, sizeof(n_global));
    if (n_global != mixer.global_weights.size()) return false;  // Size mismatch
    f.read((char*)mixer.global_weights.data(), n_global * sizeof(float));

    // Read niche weights
    uint32_t n_niche;
    f.read((char*)&n_niche, sizeof(n_niche));
    if (n_niche != mixer.niche_weights.size()) return false;
    f.read((char*)mixer.niche_weights.data(), n_niche * sizeof(float));

    return true;
}

PersistentMixer::PersistentMixer() {
    // Create mixers (6 models each)
    general_mixer = std::make_unique<Mixer>(6);
    text_mixer = std::make_unique<Mixer>(6);
    code_mixer = std::make_unique<Mixer>(6);
    json_mixer = std::make_unique<Mixer>(6);

    // Create brain directory if it doesn't exist
    fs::create_directories(weights_dir);

    // Load existing weights
    load_all();
}

PersistentMixer::~PersistentMixer() {
    // Auto-save on destruction
    save_all();
}

void PersistentMixer::save_all() {
    save_mixer_weights(*general_mixer, weights_dir + "/mixer_general.weights");
    save_mixer_weights(*text_mixer, weights_dir + "/mixer_text.weights");
    save_mixer_weights(*code_mixer, weights_dir + "/mixer_code.weights");
    save_mixer_weights(*json_mixer, weights_dir + "/mixer_json.weights");
}

void PersistentMixer::load_all() {
    bool g = load_mixer_weights(*general_mixer, weights_dir + "/mixer_general.weights");
    bool t = load_mixer_weights(*text_mixer, weights_dir + "/mixer_text.weights");
    bool c = load_mixer_weights(*code_mixer, weights_dir + "/mixer_code.weights");
    bool j = load_mixer_weights(*json_mixer, weights_dir + "/mixer_json.weights");

    int loaded = g + t + c + j;
    if (loaded > 0) {
        fprintf(stderr, "[MIXER] Loaded %d pre-trained weight sets\n", loaded);
    }
}

FileType PersistentMixer::detect_file_type(const uint8_t* data, size_t len, const std::string& filename) {
    // 1. Check file extension
    std::string ext;
    size_t dot = filename.find_last_of('.');
    if (dot != std::string::npos) {
        ext = filename.substr(dot);
        std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);

        // Text files
        if (ext == ".txt" || ext == ".log" || ext == ".md" || ext == ".rst") {
            return FileType::TEXT;
        }

        // Code files
        if (ext == ".cpp" || ext == ".h" || ext == ".c" || ext == ".hpp" ||
            ext == ".py" || ext == ".js" || ext == ".ts" || ext == ".tsx" ||
            ext == ".java" || ext == ".rs" || ext == ".go" || ext == ".rb" ||
            ext == ".php" || ext == ".cs" || ext == ".swift") {
            return FileType::CODE;
        }

        // Structured data
        if (ext == ".json" || ext == ".xml" || ext == ".yaml" || ext == ".yml" ||
            ext == ".toml" || ext == ".ini" || ext == ".cfg") {
            return FileType::JSON;
        }
    }

    // 2. Content-based detection (sample first 4KB)
    size_t sample_len = std::min(len, (size_t)4096);
    std::string sample((char*)data, sample_len);

    // Check for JSON
    if (sample[0] == '{' || sample[0] == '[') {
        return FileType::JSON;
    }

    // Check for XML
    if (sample.find("<?xml") != std::string::npos ||
        sample.find("<!DOCTYPE") != std::string::npos) {
        return FileType::JSON;
    }

    // Check for code patterns
    if (sample.find("function ") != std::string::npos ||
        sample.find("class ") != std::string::npos ||
        sample.find("#include") != std::string::npos ||
        sample.find("import ") != std::string::npos ||
        sample.find("def ") != std::string::npos ||
        sample.find("const ") != std::string::npos) {
        return FileType::CODE;
    }

    // Check if mostly printable text
    int text_chars = 0;
    for (size_t i = 0; i < sample_len; i++) {
        uint8_t c = data[i];
        if ((c >= 32 && c <= 126) || c == '\n' || c == '\r' || c == '\t') {
            text_chars++;
        }
    }

    float text_ratio = (float)text_chars / (float)sample_len;
    if (text_ratio > 0.85f) {
        return FileType::TEXT;
    }

    // Default: binary
    return FileType::BINARY;
}

Mixer* PersistentMixer::get_mixer_for_type(FileType type) {
    switch (type) {
        case FileType::TEXT:   return text_mixer.get();
        case FileType::CODE:   return code_mixer.get();
        case FileType::JSON:   return json_mixer.get();
        default:               return general_mixer.get();
    }
}

Mixer* PersistentMixer::get_mixer_for_file(const std::string& file_path) {
    // Read first 4KB to detect type
    std::ifstream f(file_path, std::ios::binary);
    if (!f) return general_mixer.get();

    std::vector<uint8_t> sample(4096);
    f.read((char*)sample.data(), sample.size());
    size_t bytes_read = f.gcount();

    FileType type = detect_file_type(sample.data(), bytes_read, file_path);
    return get_mixer_for_type(type);
}

void encode(uint32_t cum, uint32_t freq, uint32_t total) {
    range /= total;
    low   += cum * range;
    range *= freq;
    // Renormalize: while top byte is equal, emit it
    while ((low ^ (low + range)) < (1u << 24)) {
        buf.push_back((uint8_t)(low >> 24));
        low   <<= 8;
        range <<= 8;
    }
    // Handle range underflow
    while (range < (1u << 16)) {
        buf.push_back((uint8_t)(low >> 24));
        range = (~low) << 8;
        low  <<= 8;
    }
}

uint32_t get_cum(uint32_t total) {
    range /= total;
    return (code - low) / range;
}

void decode(uint32_t cum, uint32_t freq) {
    low   += cum * range;
    range *= freq;
    while ((low ^ (low + range)) < (1u << 24)) {
        code  = (code  << 8) | (pos < len ? src[pos++] : 0);
        low  <<= 8;
        range <<= 8;
    }
    while (range < (1u << 16)) {
        code  = (code  << 8) | (pos < len ? src[pos++] : 0);
        range = (~low) << 8;
        low  <<= 8;
    }
}

ContextEntry() {
    memset(freq, 0, sizeof(freq));
}

static inline uint64_t make_key(const uint8_t* ctx, int order) {
    uint64_t key = (uint64_t)(order) << 32;
    for (int i = 0; i < order; ++i)
        key |= (uint64_t)ctx[i] << (i * 8);
    return key;
}

std::vector<uint8_t> ppm_encode(const uint8_t* data, size_t len) {
    // Context table (shared across all orders, keyed by (order, ctx_bytes))
    // Bounded by PPM_MAX_ENTRIES — LRU eviction not used; simply stop adding
    // new entries when table is full (model freezes but remains correct).
    std::unordered_map<uint64_t, ContextEntry> table;
    table.reserve(PPM_MAX_ENTRIES);

    // Order-0 model: always present, initialized flat (1 per symbol)
    ContextEntry order0;
    for (int s = 0; s < 256; ++s) {
        order0.freq[s] = 1;
        order0.total  += 1;
    }

    RangeEncoder enc;
    uint8_t ctx[PPM_ORDER] = {};  // sliding context window

    for (size_t i = 0; i < len; ++i) {
        uint8_t sym = data[i];
        bool encoded = false;

        // Try from highest order down to order-1
        for (int ord = PPM_ORDER; ord >= 1 && !encoded; --ord) {
            // Build context key from the last `ord` bytes
            // ctx[0] = most recent byte, ctx[ord-1] = oldest
            uint64_t key = make_key(ctx, ord);
            auto it = table.find(key);
            if (it == table.end() || it->second.freq[sym] == 0) {
                // Context not seen or symbol not in context: emit escape
                // Escape is coded as a uniform probability 1/(unique_syms+1)
                // (simplified: use 1/(total+1) for escape slot)
                if (it != table.end()) {
                    auto& e = it->second;
                    uint32_t escape_cum = e.total;  // cumulative = sum of all freqs
                    uint32_t escape_freq = 1;
                    uint32_t escape_total = e.total + 1;
                    enc.encode(escape_cum, escape_freq, escape_total);
                }
                // fall through to lower order
            } else {
                // Encode symbol in this context
                auto& e = it->second;
                // Compute cumulative frequency for sym
                uint32_t cum = 0;
                for (int s = 0; s < sym; ++s) cum += e.freq[s];
                uint32_t total = e.total + 1;  // +1 for escape slot
                enc.encode(cum, (uint32_t)e.freq[sym], total);
                encoded = true;
            }
        }

        if (!encoded) {
            // Encode with order-0 (always succeeds — all symbols present with freq≥1)
            uint32_t cum = 0;
            for (int s = 0; s < sym; ++s) cum += order0.freq[s];
            enc.encode(cum, order0.freq[sym], order0.total);
        }

        // Update all context models with sym (order 1..PPM_ORDER)
        // Update order-0 always
        if (order0.freq[sym] < 65535) {
            order0.freq[sym]++;
            order0.total++;
        }

        // Update order 1..PPM_ORDER
        for (int ord = 1; ord <= PPM_ORDER; ++ord) {
            if ((int)i < ord - 1) break;  // not enough history yet
            uint64_t key = make_key(ctx, ord);
            if (table.size() < (size_t)PPM_MAX_ENTRIES || table.count(key)) {
                auto& e = table[key];
                if (e.freq[sym] < 65535) {
                    e.freq[sym]++;
                    e.total++;
                }
            }
        }

        // Advance context window (shift right, put newest at index 0)
        for (int j = PPM_ORDER - 1; j > 0; --j)
            ctx[j] = ctx[j-1];
        ctx[0] = sym;
    }

    return enc.finish();
}

std::vector<uint8_t> ppm_decode(const uint8_t* coded, size_t coded_len, size_t sym_count) {
    std::unordered_map<uint64_t, ContextEntry> table;
    table.reserve(PPM_MAX_ENTRIES);

    ContextEntry order0;
    for (int s = 0; s < 256; ++s) {
        order0.freq[s] = 1;
        order0.total  += 1;
    }

    RangeDecoder dec;
    dec.init(coded, coded_len);

    std::vector<uint8_t> out;
    out.reserve(sym_count);

    uint8_t ctx[PPM_ORDER] = {};

    for (size_t i = 0; i < sym_count; ++i) {
        uint8_t sym = 0;
        bool decoded = false;

        for (int ord = PPM_ORDER; ord >= 1 && !decoded; --ord) {
            uint64_t key = make_key(ctx, ord);
            auto it = table.find(key);
            if (it == table.end()) continue;  // context not seen → skip (no escape emitted)

            auto& e = it->second;
            uint32_t total = e.total + 1;  // +1 for escape slot
            uint32_t target = dec.get_cum(total);

            if (target >= e.total) {
                // Escape: consume the escape coding
                dec.decode(e.total, 1);
                // Try lower order
            } else {
                // Find symbol
                uint32_t cum = 0;
                for (int s = 0; s < 256; ++s) {
                    if (e.freq[s] == 0) continue;
                    if (cum + e.freq[s] > target) {
                        sym = (uint8_t)s;
                        dec.decode(cum, e.freq[s]);
                        decoded = true;
                        break;
                    }
                    cum += e.freq[s];
                }
            }
        }

        if (!decoded) {
            // Decode from order-0
            uint32_t target = dec.get_cum(order0.total);
            uint32_t cum = 0;
            for (int s = 0; s < 256; ++s) {
                if (cum + order0.freq[s] > target) {
                    sym = (uint8_t)s;
                    dec.decode(cum, order0.freq[s]);
                    break;
                }
                cum += order0.freq[s];
            }
        }

        out.push_back(sym);

        // Update models (same as encoder)
        if (order0.freq[sym] < 65535) {
            order0.freq[sym]++;
            order0.total++;
        }
        for (int ord = 1; ord <= PPM_ORDER; ++ord) {
            if ((int)i < ord - 1) break;
            uint64_t key = make_key(ctx, ord);
            if (table.size() < (size_t)PPM_MAX_ENTRIES || table.count(key)) {
                auto& e = table[key];
                if (e.freq[sym] < 65535) {
                    e.freq[sym]++;
                    e.total++;
                }
            }
        }

        for (int j = PPM_ORDER - 1; j > 0; --j)
            ctx[j] = ctx[j-1];
        ctx[0] = sym;
    }

    return out;
}

uint16_t fp32_to_fp16(float value) {
    uint32_t f32 = *reinterpret_cast<uint32_t*>(&value);

    // Extract sign, exponent, mantissa from FP32
    uint32_t sign = (f32 >> 16) & 0x8000;       // Sign bit at position 15
    int32_t exponent = ((f32 >> 23) & 0xFF) - 127;  // Remove FP32 bias
    uint32_t mantissa = f32 & 0x7FFFFF;         // 23-bit mantissa

    // Handle special cases
    if (exponent == 128) {
        // Infinity or NaN
        return sign | 0x7C00 | (mantissa != 0 ? 0x0200 : 0);  // Preserve NaN
    }

    if (exponent > 15) {
        // Overflow → Infinity
        return sign | 0x7C00;
    }

    if (exponent < -14) {
        // Underflow → Zero or denormal
        if (exponent < -24) {
            return sign;  // Too small, return signed zero
        }
        // Denormal number
        mantissa = (mantissa | 0x800000) >> (1 - exponent - 14);
        return sign | (mantissa >> 13);
    }

    // Normal number
    uint32_t fp16_exp = (exponent + 15) << 10;  // Add FP16 bias
    uint32_t fp16_mantissa = mantissa >> 13;     // Truncate to 10 bits

    return sign | fp16_exp | fp16_mantissa;
}

