    return result;
}

static std::vector<std::string> load_json_array(const std::string& file_path) {
    std::vector<std::string> result;

    std::ifstream file(file_path);
    if (!file) {
        std::cerr << "[RLHF] Error: Cannot open " << file_path << "\n";
        return result;
    }

    std::string content((std::istreambuf_iterator<char>(file)),
                        std::istreambuf_iterator<char>());

    // Simple JSON array parser
    size_t pos = 0;
    int brace_depth = 0;
    size_t object_start = std::string::npos;

    for (size_t i = 0; i < content.size(); i++) {
        if (content[i] == '{') {
            if (brace_depth == 0) object_start = i;
            brace_depth++;
        } else if (content[i] == '}') {
            brace_depth--;
            if (brace_depth == 0 && object_start != std::string::npos) {
                result.push_back(content.substr(object_start, i - object_start + 1));
                object_start = std::string::npos;
            }
        }
    }

    return result;
}

std::vector<std::string> load_json_array(const std::string& file_path) {
    std::vector<std::string> result;

    std::ifstream file(file_path);
    if (!file) {
        return result;  // Empty array if file doesn't exist
    }

    std::string content((std::istreambuf_iterator<char>(file)),
                        std::istreambuf_iterator<char>());

    // Simple JSON array parser - find objects between { and }
    size_t pos = 0;
    int brace_depth = 0;
    size_t object_start = std::string::npos;

    for (size_t i = 0; i < content.size(); i++) {
        if (content[i] == '{') {
            if (brace_depth == 0) {
                object_start = i;
            }
            brace_depth++;
        } else if (content[i] == '}') {
            brace_depth--;
            if (brace_depth == 0 && object_start != std::string::npos) {
                std::string obj = content.substr(object_start, i - object_start + 1);
                result.push_back(obj);
                object_start = std::string::npos;
            }
        }
    }

    return result;
}

