    for (const auto& c : covered_chars) {
        if (piece_to_id_.find(c) == piece_to_id_.end()) {
            vocab_.emplace_back(c, -10.0f, next_id);  // Initial log prob
            piece_to_id_[c] = next_id;
            next_id++;
