void VectorIndex::save(const std::string& path) const {
    std::ofstream f(path, std::ios::binary);
    if (!f) throw std::runtime_error("Cannot open index file for writing");

    // Write magic and version
    uint32_t magic = 0x42524149;  // "BRAI" in hex
    uint32_t version = 1;
    f.write((char*)&magic, sizeof(magic));
    f.write((char*)&version, sizeof(version));

    // Write entry count
    uint32_t count = entries.size();
    f.write((char*)&count, sizeof(count));

    // Write each entry
    for (const auto& e : entries) {
        // Write topic (length + data)
        uint32_t len = e.topic.size();
        f.write((char*)&len, sizeof(len));
        f.write(e.topic.data(), len);

        // Write file_path
        len = e.file_path.size();
        f.write((char*)&len, sizeof(len));
        f.write(e.file_path.data(), len);

        // Write embedding
        uint32_t emb_size = e.embedding.size();
        f.write((char*)&emb_size, sizeof(emb_size));
        f.write((char*)e.embedding.data(), emb_size * sizeof(float));

        // Write metadata
        f.write((char*)&e.original_size, sizeof(e.original_size));
        f.write((char*)&e.compressed_size, sizeof(e.compressed_size));
        f.write((char*)&e.timestamp, sizeof(e.timestamp));

        // Write content_hash
        len = e.content_hash.size();
        f.write((char*)&len, sizeof(len));
        f.write(e.content_hash.data(), len);
    }
}

void VectorIndex::load(const std::string& path) {
    std::ifstream f(path, std::ios::binary);
    if (!f) return;  // File doesn't exist yet (first run)

    // Read magic and version
    uint32_t magic, version;
    f.read((char*)&magic, sizeof(magic));
    f.read((char*)&version, sizeof(version));

    if (magic != 0x42524149) {
        throw std::runtime_error("Invalid index file (bad magic)");
    }
    if (version != 1) {
        throw std::runtime_error("Unsupported index version");
    }

    entries.clear();

    // Read entry count
    uint32_t count;
    f.read((char*)&count, sizeof(count));
    entries.reserve(count);

    // Read each entry
    for (uint32_t i = 0; i < count; i++) {
        KnowledgeEntry e;

        // Read topic
        uint32_t len;
        f.read((char*)&len, sizeof(len));
        e.topic.resize(len);
        f.read(&e.topic[0], len);

        // Read file_path
        f.read((char*)&len, sizeof(len));
        e.file_path.resize(len);
        f.read(&e.file_path[0], len);

        // Read embedding
        uint32_t emb_size;
        f.read((char*)&emb_size, sizeof(emb_size));
        e.embedding.resize(emb_size);
        f.read((char*)e.embedding.data(), emb_size * sizeof(float));

        // Read metadata
        f.read((char*)&e.original_size, sizeof(e.original_size));
        f.read((char*)&e.compressed_size, sizeof(e.compressed_size));
        f.read((char*)&e.timestamp, sizeof(e.timestamp));

        // Read content_hash
        f.read((char*)&len, sizeof(len));
        e.content_hash.resize(len);
        f.read(&e.content_hash[0], len);

        entries.push_back(std::move(e));
    }
}

HttpResponse fetch_url(const std::string& url) {
    HttpResponse resp;
    resp.status_code = -1;

    // Parse URL
    std::wstring wide_url(url.begin(), url.end());

    URL_COMPONENTS urlComp = {0};
    urlComp.dwStructSize = sizeof(urlComp);
    wchar_t hostName[256] = {0};
    wchar_t urlPath[2048] = {0};
    urlComp.lpszHostName = hostName;
    urlComp.dwHostNameLength = 256;
    urlComp.lpszUrlPath = urlPath;
    urlComp.dwUrlPathLength = 2048;

    if (!WinHttpCrackUrl(wide_url.c_str(), 0, 0, &urlComp)) {
        resp.body = "Error: Invalid URL";
        return resp;
    }

    // Initialize WinHTTP
    HINTERNET hSession = WinHttpOpen(
        L"SmartBrain/1.0",
        WINHTTP_ACCESS_TYPE_DEFAULT_PROXY,
        WINHTTP_NO_PROXY_NAME,
        WINHTTP_NO_PROXY_BYPASS,
        0
    );

    if (!hSession) {
        resp.body = "Error: Cannot initialize HTTP session";
        return resp;
    }

    // Connect
    HINTERNET hConnect = WinHttpConnect(
        hSession,
        hostName,
        urlComp.nPort,
        0
    );

    if (!hConnect) {
        WinHttpCloseHandle(hSession);
        resp.body = "Error: Cannot connect to host";
        return resp;
    }

    // Open request
    DWORD flags = (urlComp.nScheme == INTERNET_SCHEME_HTTPS) ? WINHTTP_FLAG_SECURE : 0;
    HINTERNET hRequest = WinHttpOpenRequest(
        hConnect,
        L"GET",
        urlPath,
        NULL,
        WINHTTP_NO_REFERER,
        WINHTTP_DEFAULT_ACCEPT_TYPES,
        flags
    );

    if (!hRequest) {
        WinHttpCloseHandle(hConnect);
        WinHttpCloseHandle(hSession);
        resp.body = "Error: Cannot create request";
        return resp;
    }

    // Send request
    BOOL bResults = WinHttpSendRequest(
        hRequest,
        WINHTTP_NO_ADDITIONAL_HEADERS,
        0,
        WINHTTP_NO_REQUEST_DATA,
        0,
        0,
        0
    );

    if (bResults) {
        bResults = WinHttpReceiveResponse(hRequest, NULL);
    }

    if (bResults) {
        // Get status code
        DWORD statusCode = 0;
        DWORD dwSize = sizeof(statusCode);
        WinHttpQueryHeaders(
            hRequest,
            WINHTTP_QUERY_STATUS_CODE | WINHTTP_QUERY_FLAG_NUMBER,
            WINHTTP_HEADER_NAME_BY_INDEX,
            &statusCode,
            &dwSize,
            WINHTTP_NO_HEADER_INDEX
        );
        resp.status_code = statusCode;

        // Read data
        std::string body;
        DWORD dwAvailable = 0;
        do {
            dwAvailable = 0;
            if (!WinHttpQueryDataAvailable(hRequest, &dwAvailable)) break;

            if (dwAvailable > 0) {
                char* buffer = new char[dwAvailable + 1];
                DWORD dwRead = 0;

                if (WinHttpReadData(hRequest, buffer, dwAvailable, &dwRead)) {
                    buffer[dwRead] = 0;
                    body.append(buffer, dwRead);
                }

                delete[] buffer;
            }
        } while (dwAvailable > 0);

        resp.body = body;
        resp.content_length = body.size();
    } else {
        resp.body = "Error: Request failed";
    }

    // Cleanup
    WinHttpCloseHandle(hRequest);
    WinHttpCloseHandle(hConnect);
    WinHttpCloseHandle(hSession);

    return resp;
}

HttpResponse fetch_url(const std::string& url) {
    HttpResponse resp;
    resp.status_code = -1;

    // Use curl command-line tool
    std::string temp_file = "/tmp/smart_brain_download.tmp";
    std::string cmd = "curl -L -s -o " + temp_file + " -w \"%{http_code}\" \"" + url + "\"";

    FILE* pipe = popen(cmd.c_str(), "r");
    if (!pipe) {
        resp.body = "Error: Cannot execute curl";
        return resp;
    }

    char buffer[128];
    std::string status_str;
    while (fgets(buffer, sizeof(buffer), pipe)) {
        status_str += buffer;
    }
    pclose(pipe);

    // Parse status code
    try {
        resp.status_code = std::stoi(status_str);
    } catch (...) {
        resp.status_code = -1;
    }

    // Read downloaded file
    std::ifstream f(temp_file, std::ios::binary);
    if (f) {
        resp.body.assign(
            (std::istreambuf_iterator<char>(f)),
            std::istreambuf_iterator<char>()
        );
        resp.content_length = resp.body.size();
    }

    // Cleanup
    std::remove(temp_file.c_str());

    return resp;
}

bool download_to_file(const std::string& url, const std::string& output_path) {
    auto resp = fetch_url(url);
    if (resp.status_code != 200) return false;

    std::ofstream f(output_path, std::ios::binary);
    if (!f) return false;

    f.write(resp.body.data(), resp.body.size());
    return true;
}

bool download_to_file(const std::string& url, const std::string& output_path) {
