async def chat(req: ChatRequest):
    """
    Conversational AI chat endpoint for desktop UI.
    Updated to use the unified C++ Agentic Brain (Reason + Act + Tools).
    """
    try:
        user_message = req.message
        if "User request:\n" in req.message:
            user_message = req.message.split("User request:\n", 1)[1].strip()
        else:
            user_message = req.message.strip()

        quick_reply = small_talk_reply(user_message)
        if quick_reply:
            return {
                "response": quick_reply,
                "tool": "small_talk_fast_path",
                "status": "ok",
                "confidence": 100
            }

        task_prep = TASK_INTELLIGENCE.prepare_task(user_message, req.web_search) if TASK_INTELLIGENCE else None

        if req.web_search and task_prep and task_prep.get("allow_web_lookup"):
            web_summary = quick_web_summary(user_message)
            if web_summary:
                return {
                    "response": web_summary,
                    "tool": "quick_web_summary",
                    "status": "ok",
                    "confidence": 88,
                    "analysis": build_analysis_payload(task_prep),
                }
            return run_fast_local_chat(req, user_message, task_prep)

        if task_prep and task_prep.get("route") == "fast_local_chat":
            return run_fast_local_chat(req, user_message, task_prep)

        if task_prep and task_prep.get("route") == "modify_chat":
            return run_modify_chat(req, user_message, task_prep)

        if task_prep and task_prep.get("route") == "review_chat":
            return run_review_chat(req, user_message, task_prep)

        if task_prep and task_prep.get("route") == "context_chat":
            return run_context_chat(req, user_message, task_prep)

        if not task_prep and should_use_fast_chat(user_message, req.web_search):
            return run_fast_local_chat(req, user_message)

        if not task_prep and is_review_request and is_review_request(user_message):
            return run_review_chat(req, user_message)

        if not task_prep and should_use_context_chat(user_message):
            return run_context_chat(req, user_message)

        print(f"[AGENT] Received request: {user_message[:100]}...", flush=True)
        agent_task = build_agent_task(req, task_prep)

        # Use agent_task for all requests - it's our most powerful tool
        # It handles code generation, review, and general questions
        cmd = [NEURAL_ENGINE_EXE, "agent_task", agent_task]

        # Increased timeout for agent reasoning and tool execution
        result = subprocess.run(
            cmd, 
            capture_output=True, 
            text=True, 
            encoding='utf-8', 
            errors='ignore', 
            timeout=180, 
            cwd=BASE_DIR
        )

        if result.stdout:
            # Look for FINAL_ANSWER in the agentic output
            output = result.stdout
            final_matches = re.findall(r'FINAL_ANSWER:\s*(.*?)(?:\n--- TASK COMPLETED ---|\Z)', output, re.DOTALL)

            if final_matches:
                answer = final_matches[-1].strip()
            else:
                # If no FINAL_ANSWER, just return the whole output (stripped)
                answer = output.strip()

            # Extract reasoning steps for the UI
            reasoning_steps = [line.strip() for line in output.split('\n') if "Thought:" in line or "Executing" in line]

            return {
                "response": answer,
                "tool": "local_agent",
                "status": "ok",
                "reasoning_steps": reasoning_steps,
                "confidence": 95 if final_matches else 70
            }
        else:
            print(f"[AGENT] Command failed: {result.stderr[:200]}", flush=True)
            # Fallback to Python brain if available
            if PYTHON_BRAIN_AVAILABLE and _brain:
                response_text = _brain.generate_response(user_message)
                return {
                    "response": response_text,
                    "tool": "python_brain_fallback",
                    "status": "ok"
                }
            return {
                "response": f"Neural Agent error: {result.stderr[:500]}",
                "tool": "error",
                "status": "error"
            }

    except subprocess.TimeoutExpired:
        return {"response": "Request timeout - the agent is thinking too hard. Try a simpler question.", "tool": "timeout", "status": "error"}
    except Exception as e:
        return {"response": f"Chat error: {str(e)}", "tool": "error", "status": "error"}

