        import json
        import re

        # Find JSON response at the end
        cleaned = re.sub(r'[\\x00-\\x08\\x0b\\x0c\\x0e-\\x1f\\x7f-\\x9f]', '', result.stdout).strip()
        json_match = re.search(r'\\{.*\\}', cleaned, re.DOTALL)

