def detect_intent(text: str) -> List[Dict]:
    """
    Detect user intent from natural language.
    Returns ranked list of possible intents with confidence.
    """
    lower = text.lower().strip()
    results = []

    for intent_name, patterns, weight in INTENT_PATTERNS:
        score = 0.0
        matched_patterns = []

        for pattern in patterns:
            if pattern in lower:
                # Exact words get higher score than substrings
                pattern_words = pattern.split()
                text_words = lower.split()

                if all(w in text_words for w in pattern_words):
                    score += weight * 1.0  # Word-level match
                else:
                    score += weight * 0.6  # Substring match
                matched_patterns.append(pattern)

        if score > 0:
            results.append({
                "intent": intent_name,
                "confidence": min(score, 1.0),
                "matched": matched_patterns,
            })

    # Sort by confidence
    results.sort(key=lambda x: x["confidence"], reverse=True)
    return results

def extract_entity(text: str, intent: str) -> Dict:
    """Extract relevant entities (file paths, topics, questions) from text based on intent."""
    entities = {}

    # File path extraction
    path_patterns = [
        r'([A-Za-z]:\\[^\s"\'<>|]+)',  # Windows: C:\path\file
        r'((?:\./|\.\./)[\w/\\.\-]+)',   # Relative: ./path or ../path
        r'(/[\w/.\-]+)',                  # Unix: /path/file
    ]
    for pattern in path_patterns:
        match = re.search(pattern, text)
        if match:
            entities["file_path"] = match.group(1)
            break

    # URL extraction
    url_match = re.search(r'(https?://\S+)', text)
    if url_match:
        entities["url"] = url_match.group(1)

    # Topic extraction (for learn intent)
    if intent == "learn":
        colon_idx = text.find(':')
        if colon_idx > 0:
            topic_part = re.sub(r'^(learn|teach|remember)\s*', '', text, flags=re.I).strip()
            colon_in_topic = topic_part.find(':')
            if colon_in_topic > 0:
                entities["topic"] = topic_part[:colon_in_topic].strip()
                entities["content"] = topic_part[colon_in_topic+1:].strip()

    # Question extraction (for ask intent)
    if intent == "ask":
        entities["question"] = text.strip()

    # Math expression extraction
    if intent == "math":
        expr = re.sub(r'^(calculate|compute|solve|math|calc)\s*', '', text, flags=re.I).strip()
        entities["expression"] = expr

    # Command extraction
    if intent == "cmd":
        cmd = re.sub(r'^(cmd|run|execute)\s*', '', text, flags=re.I).strip()
        entities["command"] = cmd

    return entities

def add_turn(self, user_msg: str, ai_response: str, intent: str, entities: Dict):
    """Record a conversation turn."""
    turn = {
        "user": user_msg,
        "ai": ai_response[:300],  # Truncate for memory
        "intent": intent,
        "entities": entities,
        "timestamp": time.time(),
    }
    self.history.append(turn)

    # Update state
    self.last_intent = intent
    if "file_path" in entities:
        self.current_file = entities["file_path"]
    if "topic" in entities:
        self.current_topic = entities["topic"]
        if entities["topic"] not in self.topics_discussed:
            self.topics_discussed.append(entities["topic"])

    # Trim history
    if len(self.history) > self.max_history:
        self.history = self.history[-self.max_history:]

def get_context_summary(self) -> str:
    """Get a summary of the conversation context."""
    parts = []
    if self.current_topic:
        parts.append(f"Current topic: {self.current_topic}")
    if self.current_file:
        parts.append(f"Current file: {self.current_file}")
    if self.topics_discussed:
        parts.append(f"Topics discussed: {', '.join(self.topics_discussed[-5:])}")
    return "; ".join(parts) if parts else "No context yet"

def is_followup(self, text: str) -> bool:
    """Check if user's message is a follow-up to previous conversation."""
    lower = text.lower()
    followup_indicators = [
        "it", "that", "this", "those", "these", "the same",
        "also", "and", "more", "another", "again", "what about",
        "how about", "similarly", "likewise", "as well", "too",
        "tell me more", "go on", "continue", "elaborate",
    ]
    # Short messages that refer to previous context
    if len(lower.split()) <= 4:
        for indicator in followup_indicators:
            if indicator in lower:
                return True
    return bool(self.last_intent and len(lower.split()) <= 3)

def resolve_references(self, text: str) -> str:
    """Replace pronouns and references with actual entities from context."""
    lower = text.lower()
    resolved = text

    # "it" / "that file" → current file
    if self.current_file and any(ref in lower for ref in ["it", "that file", "the file", "same file", "this file"]):
        for ref in ["that file", "the file", "same file", "this file", "it"]:
            if ref in lower:
                resolved = resolved.replace(ref, self.current_file)
                break

    # "that topic" → current topic
    if self.current_topic and "that" in lower and "topic" in lower:
        resolved = resolved.replace("that topic", self.current_topic)

    return resolved

def should_index_file(file_path):
    """Check if file should be indexed"""
    # Check extension
    if not any(str(file_path).endswith(ext) for ext in INDEXABLE_EXTENSIONS):
        return False

    # Check size (skip files > 1 MB)
    try:
        if file_path.stat().st_size > 1024 * 1024:
            return False
    except:
        return False

    # Check if in skip folder
    for skip in SKIP_FOLDERS:
        if skip in str(file_path):
            return False

    return True

def _normalize_finding(raw: dict[str, Any]) -> dict[str, Any]:
    severity = str(raw.get("severity") or "medium").lower()
    if severity not in SEVERITY_ORDER:
        severity = "medium"
    title = str(raw.get("title") or "Review finding").strip() or "Review finding"
    file_path = str(raw.get("file") or raw.get("path") or "unknown").strip() or "unknown"
    line_start = raw.get("line_start") or raw.get("lineStart") or 1
    line_end = raw.get("line_end") or raw.get("lineEnd") or line_start
    try:
        line_start = int(line_start)
    except (TypeError, ValueError):
        line_start = 1
    try:
        line_end = int(line_end)
    except (TypeError, ValueError):
        line_end = line_start
    confidence = raw.get("confidence", 0.7)
    try:
        confidence = float(confidence)
    except (TypeError, ValueError):
        confidence = 0.7

    return {
        "title": title,
        "severity": severity,
        "file": file_path,
        "line_start": line_start,
        "line_end": max(line_start, line_end),
        "body": str(raw.get("body") or raw.get("description") or "").strip(),
        "confidence": max(0.0, min(1.0, confidence)),
    }

def normalize_review_response(raw_text: str, context: dict[str, Any]) -> dict[str, Any]:
    parsed = _extract_json(raw_text)
    if parsed:
        findings = [_normalize_finding(item) for item in parsed.get("findings", []) if isinstance(item, dict)]
        findings.sort(key=lambda item: (SEVERITY_ORDER.get(item["severity"], 9), item["file"], item["line_start"]))
        return {
            "summary": str(parsed.get("summary") or "").strip(),
            "findings": findings,
            "test_gaps": [str(item).strip() for item in parsed.get("test_gaps", []) if str(item).strip()],
            "confidence": int(parsed.get("confidence", 85)) if str(parsed.get("confidence", "")).strip() else 85,
        }

    return build_review_fallback(context)

def format_review_markdown(review: dict[str, Any]) -> str:
    lines = [review.get("summary", "").strip() or "Review completed."]

    findings = review.get("findings", [])
    if findings:
        lines.extend(["", "Findings:"])
        for finding in findings:
            location = finding["file"]
            if finding.get("line_start"):
                location += f":{finding['line_start']}"
                if finding.get("line_end") and finding["line_end"] != finding["line_start"]:
                    location += f"-{finding['line_end']}"
            lines.append(
                f"- [{finding['severity'].upper()}] {finding['title']} - {location} - {finding['body']}"
            )
    else:
        lines.extend(["", "Findings:", "- No concrete issues were identified from the available context."])

    test_gaps = [gap for gap in review.get("test_gaps", []) if gap]
    if test_gaps:
        lines.extend(["", "Test gaps:"])
        for gap in test_gaps:
            lines.append(f"- {gap}")

    return "\n".join(lines).strip()

def cpp_score_response(question: str, answer: str, timeout: int = 15) -> Dict:
    """
    Call C++ neural_engine.exe score_response <file>
    C++ scores the answer using the RewardModel (ported from Python).
    Returns {"total": 0.XX, "grade": "...", "breakdown": {...}}
    Falls back to basic Python scoring if C++ not available.
    """
    if not os.path.exists(NEURAL_ENGINE):
        # Minimal fallback — Python calculates basic score
        words = len(answer.split())
        length = 1.0 if 10 <= words <= 250 else (0.3 if words < 5 else 0.7)
        return {"total": round(length * 0.7, 3), "grade": "C  (Needs improvement)",
                "breakdown": {"length": length}}

    with tempfile.NamedTemporaryFile(
        mode='w', suffix='.txt', delete=False,
        encoding='utf-8', prefix='score_'
    ) as tmp:
        tmp.write(f"question: {question}\nanswer: {answer}\n")
        tmp_path = tmp.name

    try:
        result = subprocess.run(
            [NEURAL_ENGINE, "score_response", tmp_path],
            capture_output=True, text=True, timeout=timeout,
            cwd=str(BASE_DIR)
        )
        if result.stdout:
            try:
                return json.loads(result.stdout.strip())
            except json.JSONDecodeError:
                pass
    except Exception:
        pass
    finally:
        try: os.unlink(tmp_path)
        except: pass

    return {"total": 0.5, "grade": "C  (Needs improvement)", "breakdown": {}}

def cpp_cai_critique(question: str, answer: str, timeout: int = 15) -> Dict:
    """
    Call C++ neural_engine.exe cai_critique <file>
    C++ checks the answer against CONSTITUTION rules.
    Returns {"violations": [...], "cai_score": 0.XX, "passed": true/false, "suggestions": [...]}
    Falls back to empty critique if C++ not available.
    """
    if not os.path.exists(NEURAL_ENGINE):
        return {"violations": [], "cai_score": 1.0, "passed": True, "suggestions": []}

    with tempfile.NamedTemporaryFile(
        mode='w', suffix='.txt', delete=False,
        encoding='utf-8', prefix='cai_'
    ) as tmp:
        tmp.write(f"question: {question}\nanswer: {answer}\n")
        tmp_path = tmp.name

    try:
        result = subprocess.run(
            [NEURAL_ENGINE, "cai_critique", tmp_path],
            capture_output=True, text=True, timeout=timeout,
            cwd=str(BASE_DIR)
        )
