            tabs={tabs}
            activeTabId={activeTabId}
            onSelectTab={setActiveTabId}
            onCloseTab={closeTab}
            canRunActive={tabs.find(t => t.id === activeTabId)?.type === 'file'}
            onRunActive={handleRunActiveFile}
            onReorderTabs={setTabs}
