                if (out) out.textContent += `\nConnecting Javascript WS to localhost:8080...`;
                window.ws = new WebSocket('ws://localhost:8080');
                window.ws.onopen = () => {
                    if (out) out.textContent += `\n[WS] Connected! Ready to command Chrome.`;
                    window.ws.send(JSON.stringify({
                        id: `conn_${Date.now()}`, type: "command", from: "vscode",
                        command: "browserAgent.connect", params: {}
                    }))
                };
                window.ws.onmessage = (m: any) => {
                    if (out) out.textContent += `\n[Chrome]: ${m.data.substring(0, 100)}...`;
                };
            }}>Connect WS API →</button>
        </div>
    );
}

export function CommandPalette({ commands, onClose }: Props) {
    const [query, setQuery] = useState('')
    const [activeIndex, setActiveIndex] = useState(0)
    const inputRef = useRef<HTMLInputElement>(null)

    const filtered = commands.filter(cmd =>
        cmd.label.toLowerCase().includes(query.toLowerCase())
    )

    useEffect(() => {
        inputRef.current?.focus()
    }, [])

    useEffect(() => {
        setActiveIndex(0)
    }, [query])

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Escape') {
            onClose()
        } else if (e.key === 'ArrowDown') {
            e.preventDefault()
            setActiveIndex(prev => Math.min(prev + 1, filtered.length - 1))
        } else if (e.key === 'ArrowUp') {
            e.preventDefault()
            setActiveIndex(prev => Math.max(prev - 1, 0))
        } else if (e.key === 'Enter') {
            if (filtered[activeIndex]) {
                filtered[activeIndex].action()
                onClose()
            }
        }
    }

    return (
        <div className="command-palette-overlay" onClick={onClose}>
            <div className="command-palette" onClick={e => e.stopPropagation()}>
                <div className="command-palette-input">
                    <Search size={16} style={{ color: 'var(--text-muted)' }} />
                    <input
                        ref={inputRef}
                        type="text"
                        placeholder="Type a command..."
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        onKeyDown={handleKeyDown}
                    />
                </div>
                <div className="command-palette-list">
                    {filtered.map((cmd, i) => {
                        const Icon = ICON_MAP[cmd.id] || Zap
                        return (
                            <div
                                key={cmd.id}
                                className={`command-item ${i === activeIndex ? 'active' : ''}`}
                                onClick={() => { cmd.action(); onClose() }}
                                onMouseEnter={() => setActiveIndex(i)}
                            >
                                <span className="command-item-icon">
                                    <Icon size={15} />
                                </span>
                                <span className="command-item-label">{cmd.label}</span>
                                {cmd.shortcut && (
                                    <span className="command-item-shortcut">
                                        <kbd>{cmd.shortcut}</kbd>
                                    </span>
                                )}
                            </div>
                        )
                    })}
                    {filtered.length === 0 && (
                        <div style={{
                            padding: 16, textAlign: 'center', color: 'var(--text-faint)', fontSize: 13
                        }}>
                            No matching commands
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

export function CompressView() {
    const [algorithm, setAlgorithm] = useState('--cmix');
    const [isCompressing, setIsCompressing] = useState(false);
    const [analysis, setAnalysis] = useState<any>(null);
    const [isAnalyzing, setIsAnalyzing] = useState(false);
    const hiddenFileInput = useRef<HTMLInputElement>(null);

    // Auto-analyze when file is selected
    const analyzeFile = async (filePath: string) => {
        if (!filePath.trim()) return;
        setIsAnalyzing(true);
        setAnalysis(null);
        try {
            const res = await fetch(`${API}/api/analyze`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ file_path: filePath })
            });
            const data = await res.json();
            if (!data.error) {
                setAnalysis(data);
                // Auto-select recommended algorithm
                if (data.ai?.recommended_algorithm) {
                    setAlgorithm(data.ai.recommended_algorithm);
                }
            }
        } catch { /* server not available */ }
        setIsAnalyzing(false);
    };

    const startCompression = async () => {
        const fp = (document.getElementById('input_file') as HTMLInputElement).value;
        const out = document.querySelector('.log-area pre');
        if (!out || !fp.trim()) return;

        setIsCompressing(true);
        out.textContent = `Neural Engine V10 starting...\nFile: ${fp}\nAlgorithm: ${algorithm}\n\n`;

        try {
            const res = await fetch(`${API}/api/compress_stream`, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ file_path: fp, algorithm: algorithm })
            });

            const reader = res.body?.getReader();
            const decoder = new TextDecoder();

            if (reader) {
                let currentText = out.textContent || '';
                while (true) {
                    const { done, value } = await reader.read();
                    if (done) break;
                    const chunk = decoder.decode(value, { stream: true });

                    for (let i = 0; i < chunk.length; i++) {
                        const c = chunk[i];
                        if (c === '\r') {
                            const lastNewline = currentText.lastIndexOf('\n');
                            if (lastNewline !== -1) {
                                currentText = currentText.substring(0, lastNewline + 1);
                            } else {
                                currentText = '';
                            }
                        } else {
                            currentText += c;
                        }
                    }

                    out.textContent = currentText;
                    if (out.parentElement) out.parentElement.scrollTop = out.parentElement.scrollHeight;
                }
            }
        } catch (e) {
            out.textContent += `\nError: ${e}`;
        }
        setIsCompressing(false);
    };

    return (
