export function DocumentViewer({ filePath, projectRoot, onEdit }: Props) {
    // projectRoot might be needed later, using it here to suppress TS6133
    void projectRoot;
    const ext = filePath.split('.').pop()?.toLowerCase() || ''
    const [content, setContent] = useState<string | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const loadDocs = async () => {
            setLoading(true)
            try {
                if (ext === 'md') {
                    const res = await window.fs?.readFile(filePath)
                    setContent(typeof res === 'string' ? res : '// Could not load markdown')
                } else if (ext === 'docx') {
                    if (window.fs?.readFileBase64) {
                        const base64 = await window.fs.readFileBase64(filePath)
                        if (base64 && !base64.error) {
                            const buffer = Uint8Array.from(atob(base64), c => c.charCodeAt(0))
                            const result = await mammoth.convertToHtml({ arrayBuffer: buffer.buffer })
                            setContent(result.value)
                        } else {
                            setContent('<p>Error loading DOCX file.</p>')
                        }
                    } else {
                        setContent('<p>fs.readFileBase64 not found</p>')
                    }
                }
            } catch (err) {
                console.error('Failed to load document', err)
                setContent('Error loading document')
            }
            setLoading(false)
        }

        if (ext === 'md' || ext === 'docx') {
            loadDocs()
        } else {
            setLoading(false)
        }
    }, [filePath, ext])

    if (loading) {
        return (
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 8, background: '#1A1D23', color: '#6B7280' }}>
                <div className="spin">
                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#4A9EFF" strokeWidth="2">
                        <path d="M21 12a9 9 0 11-6.219-8.56" />
                    </svg>
                </div>
                <span style={{ fontSize: 12 }}>Loading document...</span>
            </div>
        )
    }

    if (ext === 'pdf') {
        const normalizedPath = filePath.replace(/\\/g, '/')
        return (
            <div style={{ flex: 1, height: '100%', background: '#fff' }}>
                <webview src={`file:///${normalizedPath}`} style={{ width: '100%', height: '100%' }} plugins />
            </div>
        )
    }

    if (ext === 'md') {
        return (
            <div style={{ flex: 1, height: '100%', padding: '2rem', overflowY: 'auto', background: '#1A1D23', color: '#ABB2BF', fontFamily: 'system-ui', position: 'relative' }}>
                {onEdit && (
                    <button
                        onClick={onEdit}
                        style={{ position: 'absolute', top: 16, right: 16, padding: '6px 12px', background: '#4A9EFF', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer', fontSize: 12, fontWeight: 600 }}
                    >
                        Edit Markdown
                    </button>
                )}
                <div className="markdown-body" style={{ maxWidth: 800, margin: '0 auto', fontSize: 14, lineHeight: 1.6 }}>
                    <ReactMarkdown remarkPlugins={[remarkGfm]}>
                        {content || ''}
                    </ReactMarkdown>
                </div>
            </div>
        )
    }

    if (ext === 'docx') {
        return (
            <div style={{ flex: 1, height: '100%', padding: '2rem', overflowY: 'auto', background: '#fff', color: '#000', fontFamily: 'serif' }}>
                <div dangerouslySetInnerHTML={{ __html: content || 'Could not load DOCX' }} style={{ maxWidth: 800, margin: '0 auto', fontSize: 16, lineHeight: 1.6 }} />
            </div>
        )
    }

    return (
        <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#1A1D23', color: '#6B7280' }}>
            Unsupported file type: {ext}
        </div>
    )
}

export function EditorTabs({ tabs, activeTabId, onSelectTab, onCloseTab, onRunActive, canRunActive, onReorderTabs, onSplitEditor }: Props) {
    const [dragIndex, setDragIndex] = useState<number | null>(null)
    const [dragOverIndex, setDragOverIndex] = useState<number | null>(null)
    const dragRef = useRef<HTMLDivElement>(null)

    const handleDragStart = (e: React.DragEvent, index: number) => {
        setDragIndex(index)
        e.dataTransfer.effectAllowed = 'move'
        // Make drag ghost semi-transparent
        const el = e.currentTarget as HTMLElement
        el.style.opacity = '0.5'
    }

    const handleDragEnd = (e: React.DragEvent) => {
        const el = e.currentTarget as HTMLElement
        el.style.opacity = '1'

        if (dragIndex !== null && dragOverIndex !== null && dragIndex !== dragOverIndex && onReorderTabs) {
            const reordered = [...tabs]
            const [moved] = reordered.splice(dragIndex, 1)
            reordered.splice(dragOverIndex, 0, moved)
            onReorderTabs(reordered)
        }

        setDragIndex(null)
        setDragOverIndex(null)
    }

    const handleDragOver = (e: React.DragEvent, index: number) => {
        e.preventDefault()
        e.dataTransfer.dropEffect = 'move'
        setDragOverIndex(index)
    }

    const handleDragLeave = () => {
        setDragOverIndex(null)
    }

    return (
        <div className="editor-tabs-bar" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }} ref={dragRef}>
            <div style={{ display: 'flex', flex: 1, overflowX: 'auto', overflowY: 'hidden' }}>
                {tabs.map((tab, index) => (
                    <div
                        key={tab.id}
                        className={`editor-tab ${tab.id === activeTabId ? 'active' : ''} ${dragOverIndex === index ? 'drag-over' : ''}`}
                        onClick={() => onSelectTab(tab.id)}
                        draggable
                        onDragStart={(e) => handleDragStart(e, index)}
                        onDragEnd={handleDragEnd}
                        onDragOver={(e) => handleDragOver(e, index)}
                        onDragLeave={handleDragLeave}
                        onMouseDown={(e) => {
                            // Middle click to close
                            if (e.button === 1) {
                                e.preventDefault()
                                onCloseTab(tab.id)
                            }
                        }}
                    >
                        <span className="tab-icon">
                            <TabIcon type={tab.type} filename={tab.label} size={14} />
                        </span>
                        <span className="tab-label">{tab.label}</span>
                        {tab.modified && (
                            <span className="tab-dot" style={{ background: 'var(--accent)' }} />
                        )}
                        <button
                            className="tab-close"
                            onClick={(e) => { e.stopPropagation(); onCloseTab(tab.id) }}
                        >
                            <X size={12} />
                        </button>
                    </div>
                ))}
            </div>

            {/* Editor Actions */}
            <div style={{ padding: '0 8px', display: 'flex', alignItems: 'center', gap: 4 }}>
                {onSplitEditor && (
                    <button
                        className="sidebar-action-btn"
                        onClick={onSplitEditor}
                        title="Split Editor Right"
                        style={{ color: 'var(--text-muted)' }}
                    >
                        <SplitSquareHorizontal size={14} />
                    </button>
                )}
                {canRunActive && (
                    <button
                        className="sidebar-action-btn"
                        onClick={onRunActive}
                        title="Run This File"
                        style={{ color: 'var(--green)' }}
                    >
                        <Play size={14} fill="currentColor" />
                    </button>
                )}
            </div>
        </div>
    )
}

function loadExtensions(): Extension[] {
    try {
        const saved = localStorage.getItem(STORAGE_KEY)
        if (saved) {
            const savedData = JSON.parse(saved) as Record<string, boolean>
            return DEFAULT_EXTENSIONS.map(ext => ({
                ...ext,
                installed: savedData[ext.id] ?? ext.installed
            }))
        }
    } catch { }
    return DEFAULT_EXTENSIONS
}

function saveExtensionState(extensions: Extension[]) {
    try {
        const state: Record<string, boolean> = {}
        extensions.forEach(ext => { state[ext.id] = ext.installed })
        localStorage.setItem(STORAGE_KEY, JSON.stringify(state))
    } catch { }
}

export function ExtensionsPanel() {
    const [searchQuery, setSearchQuery] = useState('')
    const [extensions, setExtensions] = useState(loadExtensions)
    const [filter, setFilter] = useState<'all' | 'installed'>('all')
    const [installing, setInstalling] = useState<string | null>(null)
    const [toast, setToast] = useState('')
    const [selectedExt, setSelectedExt] = useState<Extension | null>(null)

    const showToast = (msg: string) => {
        setToast(msg)
        setTimeout(() => setToast(''), 3000)
    }

    const filtered = extensions.filter(ext => {
        if (filter === 'installed' && !ext.installed) return false
        if (searchQuery) {
            const q = searchQuery.toLowerCase()
            return ext.name.toLowerCase().includes(q) || ext.description.toLowerCase().includes(q) ||
                ext.publisher.toLowerCase().includes(q) || ext.category.toLowerCase().includes(q)
        }
        return true
    })

    const toggleInstall = async (id: string) => {
        const ext = extensions.find(e => e.id === id)
        if (!ext) return

        setInstalling(id)
        // Simulate brief install delay
        await new Promise(r => setTimeout(r, 600))

        setExtensions(prev => {
            const updated = prev.map(e =>
                e.id === id ? { ...e, installed: !e.installed } : e
            )
            saveExtensionState(updated)
            return updated
        })
        setInstalling(null)
        showToast(ext.installed ? `Uninstalled: ${ext.name}` : `Installed: ${ext.name} v${ext.version} ✓`)
    }

    const installedCount = extensions.filter(e => e.installed).length

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>
            <div className="sidebar-header">
                <span>Extensions</span>
                <span style={{ fontSize: 10, color: 'var(--text-faint)', fontWeight: 400, textTransform: 'none', letterSpacing: 0 }}>
                    {installedCount} installed
                </span>
            </div>

            {/* Toast */}
            {toast && (
                <div style={{
                    margin: '0 8px 6px', padding: '6px 10px', borderRadius: 6,
                    background: 'rgba(74,222,128,0.1)', border: '1px solid rgba(74,222,128,0.2)',
                    color: '#4ADE80', fontSize: 11, fontWeight: 600, flexShrink: 0,
                    animation: 'menuSlide 0.15s ease-out'
                }}>{toast}</div>
            )}

            {/* Search */}
            <div style={{ padding: '4px 12px 8px', flexShrink: 0 }}>
                <div style={{
                    display: 'flex', alignItems: 'center', gap: 6,
                    background: 'var(--bg-surface)', border: '1px solid var(--border)',
                    borderRadius: 6, padding: '0 8px'
                }}>
                    <Search size={13} style={{ color: 'var(--text-faint)', flexShrink: 0 }} />
                    <input
                        type="text"
                        placeholder="Search extensions..."
                        value={searchQuery}
                        onChange={e => setSearchQuery(e.target.value)}
                        style={{
                            flex: 1, background: 'transparent', border: 'none', outline: 'none',
                            color: 'var(--text)', fontSize: 12, padding: '7px 0', fontFamily: 'inherit'
                        }}
                    />
                </div>
            </div>

            {/* Filter tabs */}
            <div style={{ display: 'flex', padding: '0 12px 8px', gap: 4, flexShrink: 0 }}>
                {(['all', 'installed'] as const).map(f => (
                    <button key={f} onClick={() => setFilter(f)} style={{
                        padding: '3px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600,
                        border: '1px solid var(--border)', cursor: 'pointer', fontFamily: 'inherit',
                        background: filter === f ? 'var(--accent-soft)' : 'transparent',
                        color: filter === f ? 'var(--accent)' : 'var(--text-muted)',
                        borderColor: filter === f ? 'rgba(74,158,255,0.3)' : 'var(--border)',
                        transition: 'all 0.15s'
                    }}>
