export function FileExplorer({ projectRoot, onFileOpen }: Props) {
    const [tree, setTree] = useState<FileNode[]>([])
    const [expanded, setExpanded] = useState<Set<string>>(new Set())
    const [selected, setSelected] = useState<string>('')
    const [loading, setLoading] = useState(false)
    const [contextMenu, setContextMenu] = useState<{ x: number; y: number; node?: FileNode } | null>(null)

    const loadTree = useCallback(async () => {
        if (!window.fs?.readDir || !projectRoot) return
        setLoading(true)
        try {
            const result = await window.fs.readDir(projectRoot)
            setTree(result || [])
        } catch (e) {
            console.error('Failed to load file tree:', e)
        }
        setLoading(false)
    }, [projectRoot])

    useEffect(() => {
        loadTree()
    }, [loadTree])

    // File watcher - auto-refresh tree on filesystem changes
    useEffect(() => {
        if (!projectRoot || !(window as any).fileWatcher?.watch) return

        let refreshTimer: ReturnType<typeof setTimeout> | null = null;

        (window as any).fileWatcher.watch(projectRoot)
        const cleanup = (window as any).fileWatcher.onChange((_event: string, _filename: string) => {
            // Debounce refresh to avoid too many reloads
            if (refreshTimer) clearTimeout(refreshTimer)
            refreshTimer = setTimeout(() => {
                loadTree()
            }, 500)
        })

        return () => {
            if (refreshTimer) clearTimeout(refreshTimer)
            cleanup?.()
                ; (window as any).fileWatcher?.unwatch?.()
        }
    }, [projectRoot, loadTree])

    const toggleExpand = (path: string) => {
        setExpanded(prev => {
            const next = new Set(prev)
            if (next.has(path)) next.delete(path)
            else next.add(path)
            return next
        })
    }

    const handleClick = (node: FileNode) => {
        setSelected(node.path)
        if (node.type === 'directory') {
            toggleExpand(node.path)
        } else {
            onFileOpen(node.path, node.name)
        }
    }

    const handleContextMenu = (e: React.MouseEvent, node: FileNode) => {
        e.preventDefault()
        setContextMenu({ x: e.clientX, y: e.clientY, node })
    }

    useEffect(() => {
        if (contextMenu) {
            const close = () => setContextMenu(null)
            window.addEventListener('click', close)
            return () => window.removeEventListener('click', close)
        }
    }, [contextMenu])

    const handleDelete = async (path: string) => {
        if (window.fs?.delete) {
            await window.fs.delete(path)
            loadTree()
        }
        setContextMenu(null)
    }

    const handleNewFile = async () => {
        const name = prompt('File name:')
        if (!name) return
        const dir = selected || projectRoot
        const targetDir = selected && tree.find(n => n.path === selected && n.type === 'file')
            ? selected.substring(0, selected.lastIndexOf('\\'))
            : dir
        if (window.fs?.createFile) {
            await window.fs.createFile(`${targetDir}\\${name}`)
            loadTree()
        }
    }

    const handleNewFolder = async () => {
        const name = prompt('Folder name:')
        if (!name) return
        const dir = selected || projectRoot
        const targetDir = selected && tree.find(n => n.path === selected && n.type === 'file')
            ? selected.substring(0, selected.lastIndexOf('\\'))
            : dir
        if (window.fs?.createDir) {
            await window.fs.createDir(`${targetDir}\\${name}`)
            loadTree()
        }
    }

    const renderNode = (node: FileNode, depth: number = 0) => {
        const isExpanded = expanded.has(node.path)
        const isSelected = selected === node.path

        return (
            <div key={node.path}>
                <div
                    className={`tree-item ${isSelected ? 'selected' : ''}`}
                    style={{ '--tree-depth': depth } as React.CSSProperties}
                    onClick={() => handleClick(node)}
                    onContextMenu={(e) => handleContextMenu(e, node)}
                >
                    {node.type === 'directory' ? (
                        <>
                            <span className="tree-icon">
                                <ChevronRight size={14} className={`tree-chevron ${isExpanded ? 'open' : ''}`} />
                            </span>
                            <span className="tree-icon" style={{ color: '#E8A838' }}>
                                {isExpanded ? <FolderOpen size={15} /> : <Folder size={15} />}
                            </span>
                        </>
                    ) : (
                        <>
                            <span className="tree-icon" style={{ width: 14 }} />
                            <span className="tree-icon" style={{ color: getIconColor(node.extension || '') }}>
                                <File size={14} />
                            </span>
                        </>
                    )}
                    <span className="tree-label">{node.name}</span>
                </div>
                {node.type === 'directory' && isExpanded && node.children?.map(child => renderNode(child, depth + 1))}
            </div>
        )
    }

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>
            <div className="sidebar-header">
                <span>Explorer</span>
                <div className="sidebar-header-actions">
                    <button className="sidebar-action-btn" onClick={handleNewFile} title="New File">
                        <FilePlus size={14} />
                    </button>
                    <button className="sidebar-action-btn" onClick={handleNewFolder} title="New Folder">
                        <FolderPlus size={14} />
                    </button>
                    <button className="sidebar-action-btn" onClick={loadTree} title="Refresh">
                        <RefreshCw size={14} className={loading ? 'spin' : ''} />
                    </button>
                </div>
            </div>
            <div className="sidebar-content">
                <div className="file-tree">
                    {tree.length === 0 && !loading && (
                        <div style={{ padding: '16px', textAlign: 'center', color: 'var(--text-faint)', fontSize: 12 }}>
                            No folder opened
                        </div>
                    )}
                    {tree.map(node => renderNode(node))}
                </div>
            </div>

            {/* Context Menu */}
            {contextMenu && (
                <div className="context-menu" style={{ left: contextMenu.x, top: contextMenu.y }}>
                    <button className="context-menu-item" onClick={handleNewFile}>
                        <FilePlus size={13} /> New File
                    </button>
                    <button className="context-menu-item" onClick={handleNewFolder}>
                        <FolderPlus size={13} /> New Folder
                    </button>
                    {contextMenu.node && (
                        <>
                            <div className="context-menu-divider" />
                            <button className="context-menu-item" onClick={() => {
                                const newName = prompt('New name:', contextMenu.node!.name)
                                if (newName && window.fs?.rename) {
                                    const dir = contextMenu.node!.path.substring(0, contextMenu.node!.path.lastIndexOf('\\'))
                                    window.fs.rename(contextMenu.node!.path, `${dir}\\${newName}`).then(() => loadTree())
                                }
                                setContextMenu(null)
                            }}>
                                <Edit3 size={13} /> Rename
                            </button>
                            <button className="context-menu-item danger" onClick={() => handleDelete(contextMenu.node!.path)}>
                                <Trash2 size={13} /> Delete
                            </button>
                        </>
                    )}
                </div>
            )}
        </div>
    )
}

export function FileIcon({ filename, size = 16, className }: FileIconProps) {
    const ext = filename.split('.').pop()?.toLowerCase() || ''
    const color = ICON_COLORS[ext] || '#6B7280'
    const letter = ICON_LETTERS[ext] || ext.slice(0, 2).toUpperCase() || '?'

    // Special icons for known filenames
    const specialFiles: Record<string, { color: string; letter: string }> = {
        'package.json': { color: '#CB3837', letter: 'NP' },
        'tsconfig.json': { color: '#3178C6', letter: 'TS' },
        'vite.config.ts': { color: '#646CFF', letter: 'Vi' },
        '.eslintrc': { color: '#4B32C3', letter: 'ES' },
        '.prettierrc': { color: '#F7B93E', letter: 'Pr' },
        'README.md': { color: '#083FA1', letter: 'Rd' },
        'LICENSE': { color: '#D4AA00', letter: 'Li' },
        '.gitignore': { color: '#F14E32', letter: 'GI' },
        'Dockerfile': { color: '#2496ED', letter: 'Dk' },
    }

    const lowerName = filename.toLowerCase()
    const special = Object.entries(specialFiles).find(([k]) => lowerName === k.toLowerCase())
    const finalColor = special ? special[1].color : color
    const finalLetter = special ? special[1].letter : letter

    return (
        <svg
            width={size}
            height={size}
            viewBox="0 0 20 20"
            fill="none"
            className={`file-icon ${className || ''}`}
            style={{ flexShrink: 0 }}
        >
            {/* File shape */}
            <path
                d="M4 2.5C4 1.67 4.67 1 5.5 1H12L16 5V17.5C16 18.33 15.33 19 14.5 19H5.5C4.67 19 4 18.33 4 17.5V2.5Z"
                fill={finalColor}
                fillOpacity="0.12"
                stroke={finalColor}
                strokeWidth="0.8"
                strokeOpacity="0.5"
            />
            {/* Fold corner */}
            <path
                d="M12 1V5H16"
                stroke={finalColor}
                strokeWidth="0.8"
                strokeOpacity="0.4"
                fill={finalColor}
                fillOpacity="0.06"
            />
            {/* Extension text */}
            <text
                x="10"
                y="14"
                textAnchor="middle"
                fontSize={finalLetter.length > 2 ? '5.5' : '6.5'}
                fontWeight="700"
                fontFamily="'Inter', 'Segoe UI', Arial, sans-serif"
                fill={finalColor}
            >
                {finalLetter}
            </text>
        </svg>
    )
}

