function flattenFileTree(tree: any[], parentPath: string = ''): FileItem[] {
    const result: FileItem[] = []
    for (const node of tree) {
        const relativePath = parentPath ? `${parentPath}/${node.name}` : node.name
        if (node.type === 'file') {
            result.push({
                name: node.name,
                path: node.path,
                type: 'file',
                relativePath,
                extension: node.extension?.replace('.', '') || node.name.split('.').pop() || '',
            })
        }
        if (node.children && node.type === 'directory') {
            result.push(...flattenFileTree(node.children, relativePath))
        }
    }
    return result
}

function fuzzyMatch(query: string, text: string): { match: boolean, score: number } {
    const q = query.toLowerCase()
    const t = text.toLowerCase()

    // Exact substring match (highest priority)
    if (t.includes(q)) return { match: true, score: 100 + (100 - t.indexOf(q)) }

    // Fuzzy match
    let qi = 0
    let score = 0
    let lastMatchIndex = -1
    for (let ti = 0; ti < t.length && qi < q.length; ti++) {
        if (t[ti] === q[qi]) {
            score += 10
            // Consecutive matches get bonus
            if (lastMatchIndex === ti - 1) score += 5
            // Start-of-word bonus
            if (ti === 0 || t[ti - 1] === '/' || t[ti - 1] === '\\' || t[ti - 1] === '.' || t[ti - 1] === '-' || t[ti - 1] === '_') {
                score += 15
            }
            lastMatchIndex = ti
            qi++
        }
    }

    return { match: qi === q.length, score }
}

function highlightMatch(text: string, query: string): React.ReactElement {
    if (!query) return <>{text}</>

    const q = query.toLowerCase()
    const t = text.toLowerCase()
    const idx = t.indexOf(q)

    if (idx >= 0) {
        return (
            <>
                {text.slice(0, idx)}
                <span className="quickopen-highlight">{text.slice(idx, idx + query.length)}</span>
                {text.slice(idx + query.length)}
            </>
        )
    }

    // Fuzzy highlight
    const parts: React.ReactNode[] = []
    let qi = 0
    for (let i = 0; i < text.length; i++) {
        if (qi < q.length && t[i] === q[qi]) {
            parts.push(<span key={i} className="quickopen-highlight">{text[i]}</span>)
            qi++
        } else {
            parts.push(<span key={i}>{text[i]}</span>)
        }
    }
    return <>{parts}</>
}

export function QuickOpen({ projectRoot, onOpen, onClose, mode = 'file', initialQuery = '' }: Props) {
    const [query, setQuery] = useState(initialQuery)
    const [files, setFiles] = useState<FileItem[]>([])
    const [activeIndex, setActiveIndex] = useState(0)
    const [loading, setLoading] = useState(true)
    const [recentFiles] = useState<string[]>(() => {
        try {
            return JSON.parse(localStorage.getItem('neural-studio-recent-files') || '[]')
        } catch { return [] }
    })

    const inputRef = useRef<HTMLInputElement>(null)
    const listRef = useRef<HTMLDivElement>(null)

    // Load file tree
    useEffect(() => {
        if (!projectRoot || !window.fs?.readDir) {
            setLoading(false)
            return
        }
        window.fs.readDir(projectRoot).then((tree: any[]) => {
            setFiles(flattenFileTree(tree))
            setLoading(false)
        }).catch(() => setLoading(false))
    }, [projectRoot])

    useEffect(() => {
        inputRef.current?.focus()
    }, [])

    useEffect(() => {
        setActiveIndex(0)
    }, [query])

    // Check for Go to Line mode (query starts with :)
    const isGoToLine = query.startsWith(':')
    const isGoToSymbol = query.startsWith('@')

    // Filter and sort
    const filtered = (() => {
        if (isGoToLine || isGoToSymbol) return []
        if (!query.trim()) {
            // Show recent files first
            const recent = recentFiles
                .map(p => files.find(f => f.path === p))
                .filter(Boolean) as FileItem[]
            return recent.length > 0 ? recent : files.slice(0, 20)
        }
        return files
            .map(f => ({ file: f, ...fuzzyMatch(query, f.name + ' ' + f.relativePath) }))
            .filter(f => f.match)
            .sort((a, b) => b.score - a.score)
            .slice(0, 30)
            .map(f => f.file)
    })()

    const handleSelect = (file: FileItem) => {
        // Save to recent
        const recent = [file.path, ...recentFiles.filter(p => p !== file.path)].slice(0, 10)
        localStorage.setItem('neural-studio-recent-files', JSON.stringify(recent))
        onOpen(file.path, file.name)
        onClose()
    }

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Escape') {
            onClose()
        } else if (e.key === 'ArrowDown') {
            e.preventDefault()
            setActiveIndex(prev => Math.min(prev + 1, filtered.length - 1))
            // Scroll into view
            const el = listRef.current?.children[Math.min(activeIndex + 1, filtered.length - 1)] as HTMLElement
            el?.scrollIntoView({ block: 'nearest' })
        } else if (e.key === 'ArrowUp') {
            e.preventDefault()
            setActiveIndex(prev => Math.max(prev - 1, 0))
            const el = listRef.current?.children[Math.max(activeIndex - 1, 0)] as HTMLElement
            el?.scrollIntoView({ block: 'nearest' })
        } else if (e.key === 'Enter') {
            if (isGoToLine) {
                const lineNum = parseInt(query.slice(1))
                if (lineNum > 0) {
                    // Dispatch go-to-line event
                    window.dispatchEvent(new CustomEvent('editor-go-to-line', { detail: { line: lineNum } }))
                    onClose()
                }
            } else if (filtered[activeIndex]) {
                handleSelect(filtered[activeIndex])
            }
        }
    }

    const placeholderText = mode === 'line'
        ? 'Go to line number...'
        : 'Search files by name (prefix : for line, @ for symbol)'

    return (
        <div className="quickopen-overlay" onClick={onClose}>
            <div className="quickopen-dialog" onClick={e => e.stopPropagation()}>
                <div className="quickopen-input-row">
                    <Search size={15} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />
                    <input
                        ref={inputRef}
                        type="text"
                        className="quickopen-input"
                        placeholder={placeholderText}
                        value={query}
                        onChange={e => setQuery(e.target.value)}
                        onKeyDown={handleKeyDown}
                    />
                    <kbd className="quickopen-kbd">ESC</kbd>
                </div>

                <div className="quickopen-list" ref={listRef}>
                    {loading && (
                        <div className="quickopen-loading">
                            <div className="spin" style={{ width: 14, height: 14 }}>
                                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#4A9EFF" strokeWidth="2.5">
                                    <path d="M21 12a9 9 0 11-6.219-8.56" />
                                </svg>
                            </div>
                            <span>Indexing files...</span>
                        </div>
                    )}

                    {isGoToLine && (
                        <div className="quickopen-go-to-line">
                            <Hash size={15} style={{ color: 'var(--accent)' }} />
                            <span>Go to line <strong>{query.slice(1) || '...'}</strong></span>
                            <ArrowRight size={13} style={{ color: 'var(--text-faint)', marginLeft: 'auto' }} />
                            <span style={{ fontSize: 11, color: 'var(--text-faint)' }}>Press Enter</span>
                        </div>
                    )}

                    {!isGoToLine && !loading && !query && recentFiles.length > 0 && filtered.length > 0 && (
                        <div className="quickopen-section-label">
                            <Clock size={11} /> Recently Opened
                        </div>
                    )}

                    {!isGoToLine && filtered.map((file, i) => {
                        const ext = file.extension || ''
                        const iconColor = getFileIconColor(ext)
                        return (
                            <button
                                key={file.path}
                                className={`quickopen-item ${i === activeIndex ? 'active' : ''}`}
                                onClick={() => handleSelect(file)}
                                onMouseEnter={() => setActiveIndex(i)}
                            >
                                <File size={14} style={{ color: iconColor, flexShrink: 0 }} />
                                <span className="quickopen-item-name">
                                    {highlightMatch(file.name, query)}
                                </span>
                                <span className="quickopen-item-path">
                                    {file.relativePath}
                                </span>
                            </button>
                        )
                    })}

                    {!isGoToLine && !loading && query && filtered.length === 0 && (
                        <div className="quickopen-empty">
                            No matching files found
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

function loadConfigs(): RunConfig[] {
    try {
        const saved = localStorage.getItem(STORAGE_KEY)
        if (saved) return JSON.parse(saved)
    } catch { /* ignore */ }
    return [...DEFAULT_CONFIGS]
}

function saveConfigs(configs: RunConfig[]) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(configs))
}

export function RunPanel({ projectRoot, activeFilePath }: Props) {
    const [configs, setConfigs] = useState<RunConfig[]>(loadConfigs)
    const [selectedConfig, setSelectedConfig] = useState<number>(0)
    const [scripts, setScripts] = useState<Record<string, string>>({})
    const [loading, setLoading] = useState(true)
    const [showEditor, setShowEditor] = useState(false)
    const [editConfig, setEditConfig] = useState<RunConfig | null>(null)
    const [editIndex, setEditIndex] = useState<number>(-1)
    const [runningConfig, setRunningConfig] = useState<string | null>(null)

    // Load package.json scripts
    useEffect(() => {
        const load = async () => {
            if (!projectRoot || !window.fs?.readFile) {
                setLoading(false)
                return
            }
            try {
                const content = await window.fs.readFile(`${projectRoot}\\package.json`)
                if (content && typeof content === 'string') {
                    const pkg = JSON.parse(content)
                    if (pkg.scripts) setScripts(pkg.scripts)
                }
            } catch {
                // Not a Node.js project
            }
            setLoading(false)
        }
        load()
    }, [projectRoot])

    // Save configs when they change
    useEffect(() => {
        saveConfigs(configs)
    }, [configs])

    // Resolve variables in command
    const resolveCommand = useCallback((cmd: string): string => {
        const fileName = activeFilePath?.split(/[/\\]/).pop() || ''
        const fileDir = activeFilePath ? activeFilePath.substring(0, activeFilePath.lastIndexOf(/[/\\]/.test(activeFilePath) ? (activeFilePath.includes('/') ? '/' : '\\') : '\\')) : projectRoot
        const relPath = activeFilePath?.startsWith(projectRoot)
            ? activeFilePath.slice(projectRoot.length + 1)
            : activeFilePath || ''

        return cmd
            .replace(/\$\{file\}/g, `"${relPath}"`)
            .replace(/\$\{fileBasename\}/g, fileName)
            .replace(/\$\{fileDir\}/g, fileDir)
            .replace(/\$\{workspaceFolder\}/g, projectRoot)
    }, [activeFilePath, projectRoot])

    const runConfig = useCallback((config: RunConfig) => {
        const cmd = resolveCommand(config.command + (config.args ? ' ' + config.args : ''))
        setRunningConfig(config.name)

        // Open terminal panel
        window.dispatchEvent(new CustomEvent('open-bottom-panel', { detail: { tab: 'terminal' } }))

        setTimeout(() => {
            window.dispatchEvent(new CustomEvent('run-terminal-command', { detail: { cmd } }))
            // Clear running state after a delay
            setTimeout(() => setRunningConfig(null), 2000)
        }, 300)
    }, [resolveCommand])

    const runSelected = useCallback(() => {
        if (configs[selectedConfig]) {
            runConfig(configs[selectedConfig])
        }
    }, [configs, selectedConfig, runConfig])

    const addConfig = () => {
        setEditConfig({
            name: 'New Configuration',
            type: 'custom',
            command: '',
        })
        setEditIndex(-1)
        setShowEditor(true)
    }

    const editExisting = (index: number) => {
        setEditConfig({ ...configs[index] })
        setEditIndex(index)
        setShowEditor(true)
    }

    const saveEditConfig = () => {
        if (!editConfig || !editConfig.name.trim() || !editConfig.command.trim()) return
        if (editIndex >= 0) {
            setConfigs(prev => prev.map((c, i) => i === editIndex ? editConfig : c))
        } else {
            setConfigs(prev => [...prev, editConfig])
        }
        setShowEditor(false)
        setEditConfig(null)
    }

    const deleteConfig = (index: number) => {
        setConfigs(prev => prev.filter((_, i) => i !== index))
        if (selectedConfig >= index && selectedConfig > 0) {
            setSelectedConfig(selectedConfig - 1)
        }
    }

    const resetDefaults = () => {
        setConfigs([...DEFAULT_CONFIGS])
        setSelectedConfig(0)
    }

    const typeColors: Record<string, string> = {
        node: '#4ADE80',
        python: '#3776AB',
        npm: '#CB3837',
        custom: '#FBBF24',
        dart: '#0175C2',
        go: '#00ADD8',
        cpp: '#659AD2',
        java: '#ED8B00',
        shell: '#4EAA25',
    }

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', background: 'var(--bg-surface)', overflow: 'hidden' }}>
            <div className="sidebar-header">
                <span>Run & Debug</span>
                <div className="sidebar-header-actions">
                    <button className="sidebar-action-btn" onClick={addConfig} title="Add Configuration">
                        <Plus size={14} />
                    </button>
                    <button className="sidebar-action-btn" onClick={resetDefaults} title="Reset to Defaults">
                        <RefreshCw size={14} />
                    </button>
                    <button className="sidebar-action-btn" onClick={() => setShowEditor(!showEditor)} title="Edit Configurations">
                        <Settings size={14} />
                    </button>
                </div>
            </div>

            <div className="sidebar-content" style={{ padding: '8px 12px' }}>
                {/* Run bar */}
                <div className="run-config-bar">
                    <button
                        className="run-config-play"
                        onClick={runSelected}
                        disabled={!configs[selectedConfig]}
                        title="Run Selected Configuration (F5)"
                    >
                        <Play size={14} fill="currentColor" />
                    </button>
                    <div className="run-config-select-wrap">
                        <select
                            className="run-config-select"
                            value={selectedConfig}
                            onChange={(e) => setSelectedConfig(Number(e.target.value))}
                        >
                            {configs.map((c, i) => (
                                <option key={i} value={i}>{c.name}</option>
                            ))}
                        </select>
                        <ChevronDown size={12} className="run-config-chevron" />
                    </div>
                </div>

                {/* Config editor */}
                {showEditor && editConfig && (
                    <div className="run-config-editor">
                        <div className="run-config-field">
                            <label>Name</label>
                            <input
                                value={editConfig.name}
                                onChange={e => setEditConfig({ ...editConfig, name: e.target.value })}
                                placeholder="Configuration name"
                            />
                        </div>
                        <div className="run-config-field">
                            <label>Type</label>
                            <select
                                value={editConfig.type}
                                onChange={e => setEditConfig({ ...editConfig, type: e.target.value as RunConfig['type'] })}
                            >
                                <option value="node">Node.js</option>
                                <option value="python">Python</option>
                                <option value="npm">npm</option>
                                <option value="dart">Dart</option>
                                <option value="go">Go</option>
                                <option value="cpp">C++</option>
                                <option value="java">Java</option>
                                <option value="shell">Shell</option>
                                <option value="custom">Custom</option>
                            </select>
                        </div>
                        <div className="run-config-field">
                            <label>Command</label>
                            <input
                                value={editConfig.command}
                                onChange={e => setEditConfig({ ...editConfig, command: e.target.value })}
                                placeholder='e.g. node "${file}" or npm run dev'
                            />
                        </div>
                        <div className="run-config-field">
                            <label>Arguments (optional)</label>
                            <input
                                value={editConfig.args || ''}
                                onChange={e => setEditConfig({ ...editConfig, args: e.target.value })}
                                placeholder="--verbose --port 3000"
                            />
                        </div>
                        <div className="run-config-hint">
                            Variables: <code>{'${file}'}</code> <code>{'${fileBasename}'}</code> <code>{'${workspaceFolder}'}</code>
                        </div>
                        <div className="run-config-editor-actions">
                            <button className="run-config-save" onClick={saveEditConfig}>
                                <Save size={12} /> Save
                            </button>
                            <button className="run-config-cancel" onClick={() => { setShowEditor(false); setEditConfig(null) }}>
                                Cancel
                            </button>
                        </div>
                    </div>
                )}

                {/* Configurations list */}
                <div style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-secondary)', marginTop: 12, marginBottom: 8, textTransform: 'uppercase' }}>
                    Configurations ({configs.length})
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                    {configs.map((config, i) => (
                        <div
                            key={i}
                            className={`run-config-item ${selectedConfig === i ? 'selected' : ''} ${runningConfig === config.name ? 'running' : ''}`}
                            onClick={() => setSelectedConfig(i)}
                            onDoubleClick={() => runConfig(config)}
                        >
                            <div className="run-config-dot" style={{ background: typeColors[config.type] || '#888' }} />
                            <div className="run-config-item-info">
                                <span className="run-config-item-name">{config.name}</span>
                                <span className="run-config-item-cmd">{config.command}</span>
                            </div>
                            <div className="run-config-item-actions">
                                <button onClick={(e) => { e.stopPropagation(); runConfig(config) }} title="Run">
                                    <Play size={11} fill="currentColor" />
                                </button>
                                <button onClick={(e) => { e.stopPropagation(); editExisting(i) }} title="Edit">
                                    <Settings size={11} />
                                </button>
                                <button onClick={(e) => { e.stopPropagation(); deleteConfig(i) }} title="Delete">
                                    <Trash2 size={11} />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Package.json scripts */}
                {Object.keys(scripts).length > 0 && (
                    <>
                        <div style={{ fontSize: 11, fontWeight: 600, color: 'var(--text-secondary)', marginTop: 16, marginBottom: 8, textTransform: 'uppercase' }}>
                            npm Scripts ({Object.keys(scripts).length})
                        </div>
                        {Object.entries(scripts).map(([name, cmd]) => (
                            <div
                                key={name}
                                className="run-config-item"
                                onClick={() => {
                                    window.dispatchEvent(new CustomEvent('run-terminal-command', { detail: { cmd: `npm run ${name}` } }))
                                }}
                            >
                                <div className="run-config-dot" style={{ background: '#CB3837' }} />
                                <div className="run-config-item-info">
                                    <span className="run-config-item-name">{name}</span>
                                    <span className="run-config-item-cmd">{cmd as string}</span>
                                </div>
                                <div className="run-config-item-actions">
                                    <button onClick={(e) => {
                                        e.stopPropagation()
                                        window.dispatchEvent(new CustomEvent('run-terminal-command', { detail: { cmd: `npm run ${name}` } }))
                                    }}>
                                        <Play size={11} fill="currentColor" />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </>
                )}

                {loading && (
                    <div style={{ color: 'var(--text-faint)', fontSize: 12, marginTop: 12 }}>Loading tasks...</div>
                )}
            </div>
        </div>
    )
}

