export function SearchPanel({ projectRoot, onFileOpen }: Props) {
    const [query, setQuery] = useState('')
    const [replaceText, setReplaceText] = useState('')
    const [showReplace, setShowReplace] = useState(false)
    const [results, setResults] = useState<SearchResult[]>([])
    const [searching, setSearching] = useState(false)
    const [expandedFiles, setExpandedFiles] = useState<Set<string>>(new Set())
    const [totalMatches, setTotalMatches] = useState(0)
    const [caseSensitive, setCaseSensitive] = useState(false)
    const [wholeWord, setWholeWord] = useState(false)
    const [useRegex, setUseRegex] = useState(false)
    const searchTimeout = useRef<any>(null)

    const doSearch = useCallback(async (q: string) => {
        if (!q || q.length < 2 || !projectRoot) {
            setResults([])
            setTotalMatches(0)
            return
        }

        setSearching(true)
        try {
            const searchApi = (window as any).searchApi
            if (searchApi?.searchFiles) {
                const res = await searchApi.searchFiles(projectRoot, q)
                setResults(res || [])
                setTotalMatches(res?.reduce((sum: number, r: SearchResult) => sum + r.matches.length, 0) || 0)
                // Auto-expand all results
                setExpandedFiles(new Set(res?.map((r: SearchResult) => r.filePath) || []))
            }
        } catch (err) {
            console.error('Search failed:', err)
        }
        setSearching(false)
    }, [projectRoot])

    const handleQueryChange = (value: string) => {
        setQuery(value)
        if (searchTimeout.current) clearTimeout(searchTimeout.current)
        searchTimeout.current = setTimeout(() => doSearch(value), 400)
    }

    const toggleExpand = (filePath: string) => {
        setExpandedFiles(prev => {
            const next = new Set(prev)
            if (next.has(filePath)) next.delete(filePath)
            else next.add(filePath)
            return next
        })
    }

    const highlightMatch = (text: string, query: string) => {
        if (!query) return <span>{text}</span>
        const idx = text.toLowerCase().indexOf(query.toLowerCase())
        if (idx === -1) return <span>{text}</span>
        return (
            <span>
                {text.substring(0, idx)}
                <span style={{ background: 'rgba(255,204,0,0.3)', color: '#FFD700', borderRadius: 2, padding: '0 1px' }}>
                    {text.substring(idx, idx + query.length)}
                </span>
                {text.substring(idx + query.length)}
            </span>
        )
    }

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>
            <div className="sidebar-header">
                <span>Search</span>
                <span style={{ fontSize: 10, color: 'var(--text-faint)', fontWeight: 400, textTransform: 'none', letterSpacing: 0 }}>
                    {totalMatches > 0 ? `${totalMatches} results in ${results.length} files` : ''}
                </span>
            </div>

            <div style={{ padding: '4px 12px 8px', flexShrink: 0 }}>
                {/* Search input */}
                <div style={{
                    display: 'flex', alignItems: 'center', gap: 4,
                    background: 'var(--bg-surface)', border: '1px solid var(--border)',
                    borderRadius: 6, padding: '0 6px', marginBottom: 4
                }}>
                    <Search size={13} style={{ color: 'var(--text-faint)', flexShrink: 0 }} />
                    <input
                        type="text"
                        placeholder="Search"
                        value={query}
                        onChange={e => handleQueryChange(e.target.value)}
                        onKeyDown={e => { if (e.key === 'Enter') doSearch(query) }}
                        style={{
                            flex: 1, background: 'transparent', border: 'none', outline: 'none',
                            color: 'var(--text)', fontSize: 12, padding: '7px 0', fontFamily: 'inherit'
                        }}
                    />
                    {/* Toggle options */}
                    <button onClick={() => setCaseSensitive(!caseSensitive)}
                        title="Match Case"
                        style={{
                            padding: '2px 4px', border: 'none', borderRadius: 3, fontSize: 11, fontWeight: 700,
                            cursor: 'pointer', fontFamily: 'monospace',
                            background: caseSensitive ? 'var(--accent-soft)' : 'transparent',
                            color: caseSensitive ? 'var(--accent)' : 'var(--text-faint)',
                        }}>Aa</button>
                    <button onClick={() => setWholeWord(!wholeWord)}
                        title="Match Whole Word"
                        style={{
                            padding: '2px 4px', border: 'none', borderRadius: 3, fontSize: 10, fontWeight: 700,
                            cursor: 'pointer', fontFamily: 'monospace',
                            background: wholeWord ? 'var(--accent-soft)' : 'transparent',
                            color: wholeWord ? 'var(--accent)' : 'var(--text-faint)',
                        }}>ab</button>
                    <button onClick={() => setUseRegex(!useRegex)}
                        title="Use Regular Expression"
                        style={{
                            padding: '2px 4px', border: 'none', borderRadius: 3, fontSize: 10, fontWeight: 700,
                            cursor: 'pointer', fontFamily: 'monospace',
                            background: useRegex ? 'var(--accent-soft)' : 'transparent',
                            color: useRegex ? 'var(--accent)' : 'var(--text-faint)',
                        }}>.*</button>
                    <button onClick={() => setShowReplace(!showReplace)}
                        title="Toggle Replace"
                        style={{
                            padding: '2px', border: 'none', borderRadius: 3,
                            cursor: 'pointer', background: 'transparent',
                            color: showReplace ? 'var(--accent)' : 'var(--text-faint)',
                            display: 'flex'
                        }}>
                        <Replace size={13} />
                    </button>
                </div>

                {/* Replace input */}
                {showReplace && (
                    <div style={{
                        display: 'flex', alignItems: 'center', gap: 4,
                        background: 'var(--bg-surface)', border: '1px solid var(--border)',
                        borderRadius: 6, padding: '0 6px'
                    }}>
                        <Replace size={13} style={{ color: 'var(--text-faint)', flexShrink: 0 }} />
                        <input
                            type="text"
                            placeholder="Replace"
                            value={replaceText}
                            onChange={e => setReplaceText(e.target.value)}
                            style={{
                                flex: 1, background: 'transparent', border: 'none', outline: 'none',
                                color: 'var(--text)', fontSize: 12, padding: '7px 0', fontFamily: 'inherit'
                            }}
                        />
                    </div>
                )}
            </div>

            {/* Loading */}
            {searching && (
                <div style={{ padding: '8px 16px', fontSize: 11, color: 'var(--accent)', display: 'flex', alignItems: 'center', gap: 6 }}>
                    <div className="spin" style={{ width: 12, height: 12 }}>
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                            <path d="M21 12a9 9 0 11-6.219-8.56" />
                        </svg>
                    </div>
                    Searching...
                </div>
            )}

            {/* Results */}
            <div style={{ flex: 1, overflowY: 'auto', overflowX: 'hidden' }}>
                {results.map(result => (
                    <div key={result.filePath}>
                        {/* File header */}
                        <div
                            onClick={() => toggleExpand(result.filePath)}
                            style={{
                                display: 'flex', alignItems: 'center', gap: 4, padding: '4px 12px',
                                cursor: 'pointer', fontSize: 12, fontWeight: 600, color: 'var(--text)',
                                transition: 'background 0.1s'
                            }}
                            onMouseEnter={e => (e.currentTarget.style.background = 'var(--bg-hover)')}
                            onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                        >
                            {expandedFiles.has(result.filePath) ?
                                <ChevronDown size={12} style={{ flexShrink: 0 }} /> :
                                <ChevronRight size={12} style={{ flexShrink: 0 }} />
                            }
                            <FileText size={12} style={{ flexShrink: 0, color: 'var(--accent)' }} />
                            <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                {result.relativePath}
                            </span>
                            <span style={{
                                marginLeft: 'auto', fontSize: 10, color: 'var(--text-faint)',
                                background: 'var(--bg-hover)', padding: '1px 5px', borderRadius: 8, flexShrink: 0
                            }}>
                                {result.matches.length}
                            </span>
                        </div>
                        {/* Matches */}
                        {expandedFiles.has(result.filePath) && result.matches.map((match, i) => (
                            <div
                                key={i}
                                onClick={() => onFileOpen(result.filePath, result.fileName)}
                                style={{
                                    display: 'flex', alignItems: 'flex-start', gap: 6, padding: '3px 12px 3px 36px',
                                    cursor: 'pointer', fontSize: 11, color: 'var(--text-muted)',
                                    transition: 'background 0.1s'
                                }}
                                onMouseEnter={e => (e.currentTarget.style.background = 'var(--bg-hover)')}
                                onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
                            >
                                <span style={{ color: 'var(--text-faint)', fontFamily: "'JetBrains Mono', monospace", fontSize: 10, minWidth: 28, textAlign: 'right', flexShrink: 0 }}>
                                    {match.line}
                                </span>
                                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 11, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                                    {highlightMatch(match.text, query)}
                                </span>
                            </div>
                        ))}
                    </div>
                ))}
                {!searching && query.length >= 2 && results.length === 0 && (
                    <div style={{ padding: 20, textAlign: 'center', color: 'var(--text-faint)', fontSize: 12 }}>
                        No results found for "{query}"
                    </div>
                )}
                {!query && (
                    <div style={{ padding: 20, textAlign: 'center', color: 'var(--text-faint)', fontSize: 12 }}>
                        Type at least 2 characters to search across your project files.
                    </div>
                )}
            </div>
        </div>
    )
}

function loadSettings(): Record<string, any> {
    try {
        const saved = localStorage.getItem(STORAGE_KEY)
        if (saved) return JSON.parse(saved)
    } catch { }
    // Return defaults
    const defaults: Record<string, any> = {}
    SECTIONS.forEach(s => s.settings.forEach(item => { defaults[item.id] = item.defaultValue }))
    return defaults
}

function saveSettings(settings: Record<string, any>) {
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(settings))
        window.dispatchEvent(new Event('settings-changed'))
    } catch { }
}

export function SettingsPanel() {
    const [activeSection, setActiveSection] = useState('appearance')
    const [settings, setSettings] = useState<Record<string, any>>(loadSettings)
    const [searchQuery, setSearchQuery] = useState('')

    const currentSection = SECTIONS.find(s => s.id === activeSection)

    const updateSetting = (id: string, value: any) => {
        setSettings(prev => {
            const next = { ...prev, [id]: value }
            saveSettings(next)
            return next
        })
    }

    const resetDefaults = () => {
        if (!confirm('Reset all settings to defaults?')) return
        const defaults: Record<string, any> = {}
        SECTIONS.forEach(s => s.settings.forEach(item => { defaults[item.id] = item.defaultValue }))
        setSettings(defaults)
        saveSettings(defaults)
    }

    // Filter all settings by search query
    const filteredSections = searchQuery
        ? SECTIONS.map(section => ({
            ...section,
            settings: section.settings.filter(item =>
                item.label.toLowerCase().includes(searchQuery.toLowerCase()) ||
                item.description.toLowerCase().includes(searchQuery.toLowerCase())
            )
        })).filter(s => s.settings.length > 0)
        : currentSection ? [currentSection] : []

    return (
        <div style={{ display: 'flex', flex: 1, overflow: 'hidden', background: 'var(--bg-surface)' }}>
            {/* Settings sidebar */}
            <div style={{
                width: 220, flexShrink: 0, borderRight: '1px solid var(--border-subtle)',
                overflow: 'auto', background: 'var(--bg-dark)', padding: '12px 0',
                display: 'flex', flexDirection: 'column'
            }}>
                <div style={{
                    padding: '8px 16px', fontSize: 11, fontWeight: 700, color: 'var(--text-secondary)',
                    textTransform: 'uppercase', letterSpacing: '0.8px', flexShrink: 0
                }}>
                    Settings
                </div>
                {/* Search */}
                <div style={{ padding: '4px 12px 8px', flexShrink: 0 }}>
                    <input
                        type="text"
                        placeholder="Search settings..."
                        value={searchQuery}
                        onChange={e => setSearchQuery(e.target.value)}
                        style={{
                            width: '100%', background: 'var(--bg-surface)', border: '1px solid var(--border)',
                            borderRadius: 6, padding: '5px 8px', color: 'var(--text)', fontSize: 11,
                            outline: 'none', fontFamily: 'inherit'
                        }}
                    />
                </div>
                <div style={{ flex: 1, overflow: 'auto' }}>
                    {SECTIONS.map(section => (
                        <button
                            key={section.id}
                            onClick={() => { setActiveSection(section.id); setSearchQuery('') }}
                            style={{
                                display: 'flex', alignItems: 'center', gap: 8, padding: '8px 16px',
                                width: '100%', border: 'none', cursor: 'pointer', fontSize: 13,
                                fontFamily: 'inherit', transition: 'all 0.1s', textAlign: 'left',
                                background: activeSection === section.id && !searchQuery ? 'var(--accent-soft)' : 'transparent',
                                color: activeSection === section.id && !searchQuery ? 'var(--accent)' : 'var(--text-secondary)',
                            }}
                            onMouseEnter={e => { if (activeSection !== section.id) e.currentTarget.style.background = 'var(--bg-hover)' }}
                            onMouseLeave={e => { if (activeSection !== section.id) e.currentTarget.style.background = 'transparent' }}
                        >
                            <section.icon size={15} />
                            {section.label}
                        </button>
                    ))}
                </div>
                {/* Reset button */}
                <div style={{ padding: '8px 12px', borderTop: '1px solid var(--border-subtle)', flexShrink: 0 }}>
                    <button onClick={resetDefaults} style={{
                        display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
                        width: '100%', padding: '6px', borderRadius: 6, border: '1px solid var(--border)',
                        background: 'transparent', color: 'var(--text-muted)', fontSize: 11,
                        cursor: 'pointer', fontFamily: 'inherit', transition: 'all 0.12s'
                    }}
                        onMouseEnter={e => { e.currentTarget.style.background = 'var(--bg-hover)'; e.currentTarget.style.color = 'var(--text)' }}
                        onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--text-muted)' }}
                    >
                        <RotateCcw size={12} /> Reset All Defaults
                    </button>
                </div>
            </div>

            {/* Settings content */}
            <div style={{ flex: 1, overflow: 'auto', padding: '24px 32px' }}>
                {filteredSections.map(section => (
                    <div key={section.id} style={{ marginBottom: 32 }}>
                        <h2 style={{ fontSize: 20, fontWeight: 700, marginBottom: 4, display: 'flex', alignItems: 'center', gap: 8 }}>
                            <section.icon size={20} style={{ color: 'var(--accent)' }} />
                            {section.label}
                        </h2>
                        <div style={{ color: 'var(--text-muted)', fontSize: 13, marginBottom: 24 }}>
                            Configure {section.label.toLowerCase()} settings
                        </div>

                        {section.settings.map(item => (
                            <div key={item.id} style={{
                                padding: '16px 0', borderBottom: '1px solid var(--border-subtle)',
                                display: 'flex', alignItems: 'center', gap: 16
                            }}>
                                <div style={{ flex: 1 }}>
                                    <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--text)' }}>
                                        {item.label}
                                    </div>
                                    <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>
                                        {item.description}
                                    </div>
                                </div>

                                {item.type === 'toggle' && (
                                    <div
                                        onClick={() => updateSetting(item.id, !settings[item.id])}
                                        style={{
                                            width: 40, height: 22, borderRadius: 11, cursor: 'pointer',
                                            background: settings[item.id] ? 'var(--accent)' : 'var(--bg-hover)',
                                            border: `1px solid ${settings[item.id] ? 'var(--accent)' : 'var(--border)'}`,
                                            position: 'relative', transition: 'all 0.2s', flexShrink: 0,
                                        }}
                                    >
                                        <div style={{
                                            width: 16, height: 16, borderRadius: '50%', background: '#fff',
                                            position: 'absolute', top: 2,
                                            left: settings[item.id] ? 20 : 2,
                                            transition: 'left 0.2s',
                                            boxShadow: '0 1px 3px rgba(0,0,0,0.3)'
                                        }} />
                                    </div>
                                )}

                                {item.type === 'select' && (
                                    <select
                                        value={settings[item.id]}
                                        onChange={e => updateSetting(item.id, e.target.value)}
                                        style={{
                                            padding: '6px 10px', borderRadius: 6, border: '1px solid var(--border)',
                                            background: 'var(--bg-card)', color: 'var(--text)', fontSize: 12,
                                            outline: 'none', cursor: 'pointer', fontFamily: 'inherit', minWidth: 150,
                                        }}
                                    >
                                        {item.options?.map(opt => (
                                            <option key={opt} value={opt}>{opt}</option>
                                        ))}
                                    </select>
                                )}

                                {item.type === 'text' && (
                                    <input
                                        type="text"
                                        value={settings[item.id]}
                                        onChange={e => updateSetting(item.id, e.target.value)}
                                        style={{
                                            padding: '6px 10px', borderRadius: 6, border: '1px solid var(--border)',
                                            background: 'var(--bg-card)', color: 'var(--text)', fontSize: 12,
                                            outline: 'none', fontFamily: 'inherit', minWidth: 200,
                                        }}
                                    />
                                )}

                                {item.type === 'number' && (
                                    <input
                                        type="number"
                                        value={settings[item.id]}
                                        onChange={e => updateSetting(item.id, parseInt(e.target.value) || 0)}
                                        min={item.min}
                                        max={item.max}
                                        style={{
                                            padding: '6px 10px', borderRadius: 6, border: '1px solid var(--border)',
                                            background: 'var(--bg-card)', color: 'var(--text)', fontSize: 12,
                                            outline: 'none', fontFamily: 'inherit', width: 80,
                                        }}
                                    />
                                )}
                            </div>
                        ))}
                    </div>
                ))}
            </div>
        </div>
    )
}

export function TerminalPanel({ activeTab, onTabChange, onClose, projectRoot, problems = [], onProblemClick }: Props) {
    const [terminals, setTerminals] = useState<TerminalInstance[]>([])
    const [activeTerminalId, setActiveTerminalId] = useState<string>('')
    const [inputValues, setInputValues] = useState<Record<string, string>>({})
    const [outputLogs, setOutputLogs] = useState<OutputEntry[]>([])

    // Terminal split state
    const [splitTerminals, setSplitTerminals] = useState<string[]>([]) // IDs in split view
    const [isSplit, setIsSplit] = useState(false)

    const outputRef = useRef<HTMLDivElement>(null)
    const outputPanelRef = useRef<HTMLDivElement>(null)
    const inputRefs = useRef<Record<string, HTMLInputElement | null>>({})

    // Create first terminal on mount
    useEffect(() => {
        if (terminals.length === 0) {
            createTerminal()
        }
    }, [])

    // Listen for server logs
    useEffect(() => {
        const handleServerLog = (e: Event) => {
            const ce = e as CustomEvent<{ text: string; type?: string }>
            if (ce.detail?.text) {
                setOutputLogs(prev => [...prev.slice(-500), {
                    timestamp: new Date().toLocaleTimeString(),
                    text: ce.detail.text,
                    type: (ce.detail.type as any) || 'server'
                }])
            }
        }
        window.addEventListener('server-log', handleServerLog)
        return () => window.removeEventListener('server-log', handleServerLog)
    }, [])

    // Auto-scroll output panel
    useEffect(() => {
        if (outputPanelRef.current && activeTab === 'output') {
            outputPanelRef.current.scrollTop = outputPanelRef.current.scrollHeight
        }
    }, [outputLogs, activeTab])

    const createTerminal = useCallback(async () => {
        const id = `term-${Date.now()}`
        const newTerm: TerminalInstance = {
            id,
            title: `Terminal ${terminals.length + 1}`,
            output: [`Neural Studio Terminal — ${new Date().toLocaleString()}\n`],
            alive: true,
        }

        setTerminals(prev => [...prev, newTerm])
        setActiveTerminalId(id)
        setInputValues(prev => ({ ...prev, [id]: '' }))

        // Spawn actual terminal process
        if (window.terminal?.spawn) {
            try {
                await window.terminal.spawn(id, projectRoot)

                window.terminal.onData(id, (data: string) => {
                    setTerminals(prev => prev.map(t =>
                        t.id === id ? { ...t, output: [...t.output, data] } : t
                    ))
                })

                window.terminal.onExit(id, (_code: number) => {
                    setTerminals(prev => prev.map(t =>
                        t.id === id ? { ...t, alive: false, output: [...t.output, '\n[Process exited]\n'] } : t
                    ))
                })
            } catch (e) {
                console.error('Failed to spawn terminal:', e)
                setTerminals(prev => prev.map(t =>
                    t.id === id ? { ...t, output: [...t.output, 'Failed to start terminal process.\n'] } : t
                ))
            }
        }
    }, [terminals.length, projectRoot])

    const closeTerminal = useCallback((id: string) => {
        if (window.terminal?.kill) {
            window.terminal.kill(id)
        }
        // Remove from split view if present
        setSplitTerminals(prev => prev.filter(sid => sid !== id))
        setTerminals(prev => {
            const next = prev.filter(t => t.id !== id)
            if (activeTerminalId === id && next.length > 0) {
                setActiveTerminalId(next[next.length - 1].id)
            }
            return next
        })
    }, [activeTerminalId])

    const clearTerminal = useCallback(() => {
        if (activeTab === 'output') {
            setOutputLogs([])
        } else {
            setTerminals(prev => prev.map(t =>
                t.id === activeTerminalId ? { ...t, output: [] } : t
            ))
        }
    }, [activeTerminalId, activeTab])

    const handleInput = useCallback((termId: string, e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            e.preventDefault()
            const cmd = inputValues[termId] || ''
            setInputValues(prev => ({ ...prev, [termId]: '' }))

            if (window.terminal?.write) {
                window.terminal.write(termId, cmd + '\n')
            }

            setTerminals(prev => prev.map(t =>
                t.id === termId ? { ...t, output: [...t.output, `> ${cmd}\n`] } : t
            ))
        }
    }, [inputValues])

    // Auto-scroll active terminal
    useEffect(() => {
        if (outputRef.current) {
            outputRef.current.scrollTop = outputRef.current.scrollHeight
        }
    }, [terminals, activeTerminalId])

    // Focus input on terminal switch
    useEffect(() => {
        inputRefs.current[activeTerminalId]?.focus()
    }, [activeTerminalId])

    // Listen for custom commands to run
    useEffect(() => {
        const handleRunCommand = (e: Event) => {
            const customEvent = e as CustomEvent<{ cmd: string }>
            const cmd = customEvent.detail?.cmd
            if (cmd && activeTerminalId && window.terminal?.write) {
                window.terminal.write(activeTerminalId, cmd + '\n')
                setTerminals(prev => prev.map(t =>
                    t.id === activeTerminalId ? { ...t, output: [...t.output, `> ${cmd}\n`] } : t
                ))
            }
        }
        window.addEventListener('run-terminal-command', handleRunCommand)
        return () => window.removeEventListener('run-terminal-command', handleRunCommand)
    }, [activeTerminalId])

    // Split terminal: show current + create new side-by-side
    const handleSplitTerminal = useCallback(async () => {
        if (isSplit) {
            // Unsplit — go back to single view
            setIsSplit(false)
            setSplitTerminals([])
            return
        }
        // Create a new terminal for the right split
        const id = `term-${Date.now()}`
        const newTerm: TerminalInstance = {
            id,
            title: `Terminal ${terminals.length + 1}`,
            output: [`Neural Studio Terminal — ${new Date().toLocaleString()}\n`],
            alive: true,
        }
        setTerminals(prev => [...prev, newTerm])
        setInputValues(prev => ({ ...prev, [id]: '' }))

        // Spawn
        if (window.terminal?.spawn) {
            try {
                await window.terminal.spawn(id, projectRoot)
                window.terminal.onData(id, (data: string) => {
                    setTerminals(prev => prev.map(t =>
                        t.id === id ? { ...t, output: [...t.output, data] } : t
                    ))
                })
                window.terminal.onExit(id, (_code: number) => {
                    setTerminals(prev => prev.map(t =>
                        t.id === id ? { ...t, alive: false, output: [...t.output, '\n[Process exited]\n'] } : t
                    ))
                })
            } catch (e) {
                console.error('Failed to spawn terminal:', e)
            }
        }

        setSplitTerminals([activeTerminalId, id])
        setIsSplit(true)
    }, [activeTerminalId, isSplit, terminals.length, projectRoot])

    const activeTerm = terminals.find(t => t.id === activeTerminalId)
    const errorCount = problems.filter(p => p.type === 'error').length
    const warningCount = problems.filter(p => p.type === 'warning').length

    // Render a single terminal pane
    const renderTerminalPane = (term: TerminalInstance, isActive: boolean) => (
        <div
            className={`terminal-split-pane ${isActive ? 'active' : ''}`}
            key={term.id}
            onClick={() => {
                setActiveTerminalId(term.id)
                inputRefs.current[term.id]?.focus()
            }}
        >
            {/* Pane header */}
            <div className="terminal-pane-header">
                <Terminal size={11} />
                <span className="terminal-pane-title">{term.title}</span>
                {!term.alive && <span className="terminal-pane-dead">exited</span>}
                {isSplit && (
                    <button
                        className="terminal-pane-maximize"
                        onClick={(e) => {
                            e.stopPropagation()
                            setIsSplit(false)
                            setSplitTerminals([])
                            setActiveTerminalId(term.id)
                        }}
                        title="Maximize"
                    >
                        <Maximize2 size={11} />
                    </button>
                )}
            </div>
            {/* Pane output */}
            <div className="terminal-output terminal-split-output" ref={isActive ? outputRef : undefined}>
                {term.output.map((line, i) => (
                    <span key={i}>{line}</span>
                ))}
            </div>
            {term.alive && (
                <div className="terminal-input-line">
                    <span className="terminal-prompt">❯</span>
                    <input
                        ref={(el) => { inputRefs.current[term.id] = el }}
                        className="terminal-input"
                        value={inputValues[term.id] || ''}
                        onChange={e => setInputValues(prev => ({ ...prev, [term.id]: e.target.value }))}
                        onKeyDown={(e) => handleInput(term.id, e)}
                        placeholder="Type a command..."
                        spellCheck={false}
                        autoFocus={isActive}
                    />
                </div>
            )}
        </div>
    )

    return (
        <>
            {/* Panel tabs bar */}
            <div className="panel-tabs-bar">
                <button
                    className={`panel-tab ${activeTab === 'terminal' ? 'active' : ''}`}
                    onClick={() => onTabChange('terminal')}
                >
                    <Terminal size={12} /> Terminal
                </button>
                <button
                    className={`panel-tab ${activeTab === 'output' ? 'active' : ''}`}
                    onClick={() => onTabChange('output')}
                >
                    <FileText size={12} /> Output
                    {outputLogs.length > 0 && (
                        <span className="panel-tab-badge">{outputLogs.length}</span>
                    )}
                </button>
                <button
                    className={`panel-tab ${activeTab === 'problems' ? 'active' : ''}`}
                    onClick={() => onTabChange('problems')}
                >
                    <AlertCircle size={12} /> Problems
                    {(errorCount + warningCount) > 0 && (
                        <span className={`panel-tab-badge ${errorCount > 0 ? 'error' : 'warning'}`}>
                            {errorCount + warningCount}
                        </span>
                    )}
                </button>

                <div className="panel-actions">
                    {/* Terminal instance tabs */}
                    {activeTab === 'terminal' && !isSplit && terminals.map(term => (
                        <button
                            key={term.id}
                            className={`panel-tab terminal-instance-tab ${term.id === activeTerminalId ? 'active' : ''}`}
                            onClick={() => setActiveTerminalId(term.id)}
                        >
                            <Terminal size={10} />
                            {term.title}
                            <span
                                className="terminal-tab-close"
                                onClick={(e) => { e.stopPropagation(); closeTerminal(term.id) }}
                            >×</span>
                        </button>
                    ))}

                    {activeTab === 'terminal' && (
                        <button
                            className={`panel-action-btn ${isSplit ? 'active' : ''}`}
                            onClick={handleSplitTerminal}
                            title={isSplit ? 'Unsplit Terminal' : 'Split Terminal Right'}
                        >
                            <Columns size={14} />
                        </button>
                    )}
                    <button className="panel-action-btn" onClick={createTerminal} title="New Terminal">
                        <Plus size={14} />
                    </button>
                    <button className="panel-action-btn" onClick={clearTerminal} title="Clear">
                        <Trash2 size={14} />
                    </button>
                    <button className="panel-action-btn" onClick={onClose} title="Close Panel">
                        <X size={14} />
                    </button>
                </div>
            </div>

            {/* Panel content */}
            <div className="panel-content">
                {activeTab === 'terminal' && (
                    <>
                        {isSplit && splitTerminals.length >= 2 ? (
                            // ── Split View ──
                            <div className="terminal-split-container">
                                {splitTerminals.map(sid => {
                                    const term = terminals.find(t => t.id === sid)
                                    if (!term) return null
                                    return renderTerminalPane(term, sid === activeTerminalId)
                                })}
                            </div>
                        ) : (
                            // ── Single View ──
                            activeTerm && (
                                <div className="terminal-container" onClick={() => inputRefs.current[activeTerminalId]?.focus()}>
                                    <div className="terminal-output" ref={outputRef}>
                                        {activeTerm.output.map((line, i) => (
                                            <span key={i}>{line}</span>
                                        ))}
                                    </div>
                                    {activeTerm.alive && (
                                        <div className="terminal-input-line">
                                            <span className="terminal-prompt">❯</span>
                                            <input
                                                ref={(el) => { inputRefs.current[activeTerminalId] = el }}
                                                className="terminal-input"
                                                value={inputValues[activeTerminalId] || ''}
                                                onChange={e => setInputValues(prev => ({ ...prev, [activeTerminalId]: e.target.value }))}
                                                onKeyDown={(e) => handleInput(activeTerminalId, e)}
                                                placeholder="Type a command..."
                                                spellCheck={false}
                                                autoFocus
                                            />
                                        </div>
                                    )}
                                </div>
                            )
                        )}
                    </>
                )}

                {activeTab === 'output' && (
                    <div className="terminal-container">
                        <div className="terminal-output output-panel" ref={outputPanelRef}>
                            {outputLogs.length === 0 ? (
                                <div className="output-empty">
                                    <FileText size={20} style={{ color: 'var(--text-faint)', opacity: 0.5 }} />
                                    <span>No output yet. Server logs and task output will appear here.</span>
                                </div>
                            ) : (
                                outputLogs.map((entry, i) => (
                                    <div key={i} className={`output-line ${entry.type}`}>
                                        <span className="output-timestamp">[{entry.timestamp}]</span>
                                        <span className="output-text">{entry.text}</span>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                )}

                {activeTab === 'problems' && (
                    <div className="terminal-container">
                        <div className="terminal-output problems-panel">
                            {problems.length === 0 ? (
                                <div className="problems-empty">
                                    <CheckCircle size={20} style={{ color: 'var(--green)' }} />
                                    <span>No problems detected in workspace.</span>
                                </div>
                            ) : (
                                <>
                                    <div className="problems-summary">
                                        {errorCount > 0 && (
                                            <span className="problems-count error">
                                                <AlertCircle size={12} /> {errorCount} error{errorCount !== 1 ? 's' : ''}
                                            </span>
                                        )}
                                        {warningCount > 0 && (
                                            <span className="problems-count warning">
                                                <AlertTriangle size={12} /> {warningCount} warning{warningCount !== 1 ? 's' : ''}
                                            </span>
                                        )}
                                    </div>
                                    {problems.map((problem, i) => (
                                        <button
                                            key={i}
                                            className={`problem-item ${problem.type}`}
                                            onClick={() => onProblemClick?.(problem.file, problem.line)}
                                        >
                                            <span className="problem-icon">
                                                {problem.type === 'error' && <AlertCircle size={13} />}
                                                {problem.type === 'warning' && <AlertTriangle size={13} />}
                                                {problem.type === 'info' && <Info size={13} />}
                                            </span>
                                            <span className="problem-message">{problem.message}</span>
                                            <span className="problem-source">{problem.source || ''}</span>
                                            <span className="problem-location">
                                                {problem.file.split(/[/\\]/).pop()}
                                                {problem.line && `:${problem.line}`}
                                                {problem.column && `:${problem.column}`}
                                            </span>
                                        </button>
                                    ))}
                                </>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </>
    )
}

export function WebViewPanel({ url: initialUrl }: Props) {
    const [currentUrl, setCurrentUrl] = useState(initialUrl || '')
    const [inputUrl, setInputUrl] = useState(initialUrl || '')
    const [isLoading, setIsLoading] = useState(false)
    const [canGoBack] = useState(false)
    const [canGoForward] = useState(false)
    const [isSecure, setIsSecure] = useState(false)
    const [bookmarks] = useState([
        { title: 'Google', url: 'https://www.google.com' },
        { title: 'GitHub', url: 'https://github.com' },
        { title: 'Stack Overflow', url: 'https://stackoverflow.com' },
        { title: 'MDN Web Docs', url: 'https://developer.mozilla.org' },
        { title: 'npm', url: 'https://www.npmjs.com' },
    ])

    const webviewRef = useRef<any>(null)

    const navigate = useCallback((url: string) => {
        let normalizedUrl = url.trim()
        if (!normalizedUrl) return

        // Auto-add protocol
        if (!normalizedUrl.startsWith('http://') && !normalizedUrl.startsWith('https://') && !normalizedUrl.startsWith('file://')) {
            if (normalizedUrl.includes('.') && !normalizedUrl.includes(' ')) {
                normalizedUrl = 'https://' + normalizedUrl
            } else {
                normalizedUrl = `https://www.google.com/search?q=${encodeURIComponent(normalizedUrl)}`
            }
        }

        setCurrentUrl(normalizedUrl)
        setInputUrl(normalizedUrl)
        setIsSecure(normalizedUrl.startsWith('https://'))
        setIsLoading(true)

        // Simulate load completion
        setTimeout(() => setIsLoading(false), 1500)
    }, [])

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            navigate(inputUrl)
        }
    }

    const goHome = () => {
        navigate('https://www.google.com')
    }

    const refresh = () => {
        if (currentUrl) {
            setIsLoading(true)
            // Re-trigger webview reload
            if (webviewRef.current) {
                webviewRef.current.reload()
            }
            setTimeout(() => setIsLoading(false), 1000)
        }
    }

    const openExternal = () => {
        if (currentUrl && window.shell?.openExternal) {
            window.shell.openExternal(currentUrl)
        }
    }

    const openDevTools = () => {
        if (webviewRef.current) {
            webviewRef.current.openDevTools()
        }
    }

    const askAIAboutPage = async () => {
        if (webviewRef.current) {
            try {
                // Execute JS in the webview to extract the page text
                const text = await webviewRef.current.executeJavaScript(`
                    (function() {
                        return document.body ? document.body.innerText.substring(0, 3000) : "No content";
                    })();
                `)
                const title = await webviewRef.current.executeJavaScript(`document.title`) || 'Webpage'
                const query = `Can you analyze this webpage for me? Title: ${title}\nURL: ${currentUrl}\n\nContent Snapshot:\n${text}`
                window.dispatchEvent(new CustomEvent('ai-chat-query', { detail: { text: query } }))
                window.dispatchEvent(new CustomEvent('open-ai-chat'))
            } catch (err) {
                console.error("Failed to read webpage contents", err)
            }
        }
    }

    // If no URL yet, show placeholder
    if (!currentUrl) {
        return (
            <div className="webview-container">
                <div className="webview-toolbar">
                    <button className="webview-nav-btn" disabled><ArrowLeft size={16} /></button>
                    <button className="webview-nav-btn" disabled><ArrowRight size={16} /></button>
                    <button className="webview-nav-btn" onClick={refresh} disabled><RotateCw size={16} /></button>
                    <button className="webview-nav-btn" onClick={goHome}><Home size={16} /></button>
                    <div className="webview-url-bar">
                        <Globe size={13} style={{ color: 'var(--text-faint)' }} />
                        <input
                            type="text"
                            placeholder="Enter URL or search..."
                            value={inputUrl}
                            onChange={e => setInputUrl(e.target.value)}
                            onKeyDown={handleKeyDown}
                        />
                    </div>
                    <button className="webview-nav-btn" disabled><ExternalLink size={16} /></button>
                </div>

                {/* Bookmarks bar */}
                <div style={{
                    display: 'flex', gap: 4, padding: '4px 10px',
                    borderBottom: '1px solid var(--border-subtle)', flexShrink: 0, overflowX: 'auto'
                }}>
                    {bookmarks.map(bm => (
                        <button key={bm.url} onClick={() => navigate(bm.url)} style={{
                            display: 'flex', alignItems: 'center', gap: 4, padding: '3px 8px',
                            borderRadius: 4, border: 'none', background: 'transparent', color: 'var(--text-muted)',
                            fontSize: 11, cursor: 'pointer', whiteSpace: 'nowrap', fontFamily: 'inherit',
                            transition: 'all 0.12s'
                        }}
                            onMouseEnter={e => { e.currentTarget.style.background = 'var(--bg-hover)'; e.currentTarget.style.color = 'var(--text)' }}
                            onMouseLeave={e => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = 'var(--text-muted)' }}
                        >
                            <Star size={10} /> {bm.title}
                        </button>
                    ))}
                </div>

                <div className="webview-placeholder">
                    <div className="webview-placeholder-icon">
                        <Globe size={28} />
                    </div>
                    <div style={{ fontSize: 16, fontWeight: 600, color: 'var(--text-secondary)' }}>
                        Built-in Browser
                    </div>
                    <div style={{ fontSize: 12, maxWidth: 300, textAlign: 'center', lineHeight: 1.6 }}>
